{
  "name": "CargoFlightBoard - Painel de Logística",
  "description": "Um painel de logística inspirado em letreiros de aeroportos para gerenciamento de equipes de apanha e cargas de aves."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum CargoStatus {
  PROGRAMADO = 'PROGRAMADO',
  CARREGANDO = 'CARREGANDO',
  FINALIZADO = 'FINALIZADO'
}

export interface Team {
  id: string;
  number: string;
  unit: string;
}

export interface Cargo {
  id: string;
  teamId: string;
  integrated: string;
  city: string;
  pickupTime: string; // HH:mm
  birdCount: number;
  totalLoad: number;
  unit: string;
  status: CargoStatus;
  startTime?: string; // HH:mm
  endTime?: string; // HH:mm
  endDate?: string; // YYYY-MM-DD
}

export type ViewMode = 'DASHBOARD' | 'TEAMS' | 'CARGO_ENTRY';

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { AirportBoard } from './components/AirportBoard';
import { TeamManager } from './components/TeamManager';
import { CargoManager } from './components/CargoManager';
import { Team, Cargo, ViewMode, CargoStatus } from './types';

const App: React.FC = () => {
  const [teams, setTeams] = useState<Team[]>(() => {
    const saved = localStorage.getItem('teams');
    return saved ? JSON.parse(saved) : [];
  });

  const [cargos, setCargos] = useState<Cargo[]>(() => {
    const saved = localStorage.getItem('cargos');
    return saved ? JSON.parse(saved) : [];
  });

  const [view, setView] = useState<ViewMode>('DASHBOARD');

  useEffect(() => {
    localStorage.setItem('teams', JSON.stringify(teams));
  }, [teams]);

  useEffect(() => {
    localStorage.setItem('cargos', JSON.stringify(cargos));
  }, [cargos]);

  // Team CRUD
  const addTeam = (team: Omit<Team, 'id'>) => {
    setTeams(prev => [...prev, { ...team, id: crypto.randomUUID() }]);
  };

  const updateTeam = (id: string, updated: Omit<Team, 'id'>) => {
    setTeams(prev => prev.map(t => t.id === id ? { ...updated, id } : t));
  };

  const deleteTeam = (id: string) => {
    setTeams(prev => prev.filter(t => t.id !== id));
    setCargos(prev => prev.filter(c => c.teamId !== id)); // Cleanup cargo for deleted team
  };

  // Cargo CRUD & Actions
  const addCargo = (cargo: Omit<Cargo, 'id' | 'status'>) => {
    setCargos(prev => [...prev, { 
      ...cargo, 
      id: crypto.randomUUID(), 
      status: CargoStatus.PROGRAMADO 
    }]);
  };

  const updateCargo = (id: string, updated: Partial<Cargo>) => {
    setCargos(prev => prev.map(c => c.id === id ? { ...c, ...updated } : c));
  };

  const deleteCargo = (id: string) => {
    setCargos(prev => prev.filter(c => c.id !== id));
  };

  const startCargo = (id: string) => {
    const now = new Date();
    const time = now.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
    updateCargo(id, { 
      status: CargoStatus.CARREGANDO, 
      startTime: time 
    });
  };

  const endCargo = (id: string) => {
    const now = new Date();
    const time = now.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
    const date = now.toISOString().split('T')[0];
    updateCargo(id, { 
      status: CargoStatus.FINALIZADO, 
      endTime: time,
      endDate: date
    });
  };

  return (
    <Layout view={view} setView={setView}>
      {view === 'DASHBOARD' && (
        <AirportBoard 
          cargos={cargos} 
          teams={teams} 
          onStart={startCargo} 
          onEnd={endCargo} 
        />
      )}
      {view === 'TEAMS' && (
        <TeamManager 
          teams={teams} 
          onAdd={addTeam} 
          onUpdate={updateTeam} 
          onDelete={deleteTeam} 
        />
      )}
      {view === 'CARGO_ENTRY' && (
        <CargoManager 
          cargos={cargos} 
          teams={teams} 
          onAdd={addCargo} 
          onUpdate={updateCargo} 
          onDelete={deleteCargo} 
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { LayoutDashboard, Users, Truck, Clock } from 'lucide-react';
import { ViewMode } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  view: ViewMode;
  setView: (v: ViewMode) => void;
}

export const Layout: React.FC<LayoutProps> = ({ children, view, setView }) => {
  const [time, setTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  return (
    <div className="min-h-screen flex flex-col bg-[#020617]">
      {/* Header */}
      <header className="bg-[#1e293b] border-b border-slate-700 px-6 py-4 flex flex-wrap justify-between items-center sticky top-0 z-50">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-yellow-500 rounded-lg text-slate-900">
            <Truck size={28} />
          </div>
          <div>
            <h1 className="text-xl font-extrabold tracking-tighter uppercase">Cargo Board</h1>
            <p className="text-xs text-slate-400 font-medium">Controle Logístico de Apanha</p>
          </div>
        </div>

        <div className="flex items-center gap-6 mt-4 sm:mt-0">
          <nav className="flex bg-[#0f172a] p-1 rounded-xl gap-1">
            <button 
              onClick={() => setView('DASHBOARD')}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold transition-all ${view === 'DASHBOARD' ? 'bg-yellow-500 text-slate-900' : 'text-slate-400 hover:text-white'}`}
            >
              <LayoutDashboard size={18} />
              <span className="hidden md:inline">Painel</span>
            </button>
            <button 
              onClick={() => setView('CARGO_ENTRY')}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold transition-all ${view === 'CARGO_ENTRY' ? 'bg-yellow-500 text-slate-900' : 'text-slate-400 hover:text-white'}`}
            >
              <Truck size={18} />
              <span className="hidden md:inline">Cargas</span>
            </button>
            <button 
              onClick={() => setView('TEAMS')}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold transition-all ${view === 'TEAMS' ? 'bg-yellow-500 text-slate-900' : 'text-slate-400 hover:text-white'}`}
            >
              <Users size={18} />
              <span className="hidden md:inline">Equipes</span>
            </button>
          </nav>

          <div className="flex items-center gap-2 bg-[#0f172a] px-4 py-2 rounded-xl border border-slate-700 airport-font text-yellow-500 font-bold min-w-[120px] justify-center">
            <Clock size={16} />
            <span>{time.toLocaleTimeString('pt-BR')}</span>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 p-4 md:p-8">
        {children}
      </main>

      {/* Footer */}
      <footer className="bg-[#0f172a] border-t border-slate-800 p-4 text-center text-slate-500 text-xs">
        &copy; {new Date().getFullYear()} CargoFlightBoard Systems - Todos os Direitos Reservados
      </footer>
    </div>
  );
};

import React from 'react';
import { Play, CheckCircle, Info } from 'lucide-react';
import { Cargo, Team, CargoStatus } from '../types';

interface AirportBoardProps {
  cargos: Cargo[];
  teams: Team[];
  onStart: (id: string) => void;
  onEnd: (id: string) => void;
}

export const AirportBoard: React.FC<AirportBoardProps> = ({ cargos, teams, onStart, onEnd }) => {
  const getTeamLabel = (teamId: string) => {
    const team = teams.find(t => t.id === teamId);
    return team ? `EQP ${team.number}` : '---';
  };

  const getStatusColor = (status: CargoStatus) => {
    switch (status) {
      case CargoStatus.PROGRAMADO: return 'text-sky-400 bg-sky-400/10 border-sky-400/20';
      case CargoStatus.CARREGANDO: return 'text-yellow-400 bg-yellow-400/10 border-yellow-400/20 status-carregando';
      case CargoStatus.FINALIZADO: return 'text-emerald-400 bg-emerald-400/10 border-emerald-400/20';
      default: return 'text-slate-400';
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between mb-4">
        <h2 className="text-2xl font-black uppercase tracking-widest text-white airport-font">
          Quadro de Partidas <span className="text-yellow-500">Logísticas</span>
        </h2>
        <div className="flex gap-4 text-xs font-bold uppercase tracking-wider text-slate-400">
          <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-sky-400"></div> Programado</div>
          <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-yellow-400"></div> Carregando</div>
          <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-emerald-400"></div> Finalizado</div>
        </div>
      </div>

      <div className="overflow-x-auto rounded-xl border border-slate-800 shadow-2xl bg-[#0f172a]">
        <table className="w-full text-left airport-font">
          <thead>
            <tr className="bg-slate-900 text-slate-400 text-xs uppercase tracking-tighter border-b border-slate-800">
              <th className="px-6 py-4">Status</th>
              <th className="px-6 py-4">Equipe</th>
              <th className="px-6 py-4">Integrado</th>
              <th className="px-6 py-4">Cidade</th>
              <th className="px-6 py-4 text-center">Hora Apanha</th>
              <th className="px-6 py-4 text-center">Aves</th>
              <th className="px-6 py-4 text-center">Carga (Kg)</th>
              <th className="px-6 py-4">Unidade</th>
              <th className="px-6 py-4 text-center">Início/Fim</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800/50">
            {cargos.length === 0 ? (
              <tr>
                <td colSpan={9} className="px-6 py-12 text-center text-slate-500 italic">
                  Nenhuma carga programada no momento.
                </td>
              </tr>
            ) : (
              cargos.map((cargo) => (
                <tr key={cargo.id} className="hover:bg-slate-800/40 transition-colors group">
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className={`px-3 py-1 rounded border text-[10px] font-black tracking-widest uppercase ${getStatusColor(cargo.status)}`}>
                      {cargo.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-white font-bold">{getTeamLabel(cargo.teamId)}</td>
                  <td className="px-6 py-4 text-slate-300 font-medium">{cargo.integrated}</td>
                  <td className="px-6 py-4 text-slate-400">{cargo.city}</td>
                  <td className="px-6 py-4 text-center text-yellow-500 font-bold">{cargo.pickupTime}</td>
                  <td className="px-6 py-4 text-center text-slate-300">{cargo.birdCount.toLocaleString()}</td>
                  <td className="px-6 py-4 text-center text-slate-300">{cargo.totalLoad.toLocaleString()}</td>
                  <td className="px-6 py-4 text-slate-400">{cargo.unit}</td>
                  <td className="px-6 py-4">
                    <div className="flex justify-center gap-2">
                      {cargo.status === CargoStatus.PROGRAMADO && (
                        <button 
                          onClick={() => onStart(cargo.id)}
                          className="p-2 bg-sky-500/10 text-sky-500 hover:bg-sky-500 hover:text-white rounded-lg transition-all"
                          title="Iniciar Carregamento"
                        >
                          <Play size={18} fill="currentColor" />
                        </button>
                      )}
                      {cargo.status === CargoStatus.CARREGANDO && (
                        <button 
                          onClick={() => onEnd(cargo.id)}
                          className="p-2 bg-emerald-500/10 text-emerald-500 hover:bg-emerald-500 hover:text-white rounded-lg transition-all"
                          title="Finalizar"
                        >
                          <CheckCircle size={18} />
                        </button>
                      )}
                      {cargo.status === CargoStatus.FINALIZADO && (
                        <div className="flex flex-col items-center text-[9px] text-slate-500 font-bold">
                          <span>I: {cargo.startTime}</span>
                          <span>F: {cargo.endTime}</span>
                        </div>
                      )}
                    </div>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-slate-900 p-4 rounded-xl border border-slate-800 flex items-center gap-4">
          <div className="p-3 bg-sky-500/10 text-sky-500 rounded-lg">
            <Info size={24} />
          </div>
          <div>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Cargas Ativas</p>
            <p className="text-2xl font-black text-white airport-font">{cargos.filter(c => c.status !== CargoStatus.FINALIZADO).length}</p>
          </div>
        </div>
        <div className="bg-slate-900 p-4 rounded-xl border border-slate-800 flex items-center gap-4">
          <div className="p-3 bg-emerald-500/10 text-emerald-500 rounded-lg">
            <CheckCircle size={24} />
          </div>
          <div>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Concluídas Hoje</p>
            <p className="text-2xl font-black text-white airport-font">{cargos.filter(c => c.status === CargoStatus.FINALIZADO).length}</p>
          </div>
        </div>
        <div className="bg-slate-900 p-4 rounded-xl border border-slate-800 flex items-center gap-4">
          <div className="p-3 bg-yellow-500/10 text-yellow-500 rounded-lg">
            <Truck size={24} />
          </div>
          <div>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Total Aves</p>
            <p className="text-2xl font-black text-white airport-font">
              {cargos.reduce((acc, curr) => acc + curr.birdCount, 0).toLocaleString()}
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Plus, Edit2, Trash2, X, Check } from 'lucide-react';
import { Team } from '../types';

interface TeamManagerProps {
  teams: Team[];
  onAdd: (team: Omit<Team, 'id'>) => void;
  onUpdate: (id: string, team: Omit<Team, 'id'>) => void;
  onDelete: (id: string) => void;
}

export const TeamManager: React.FC<TeamManagerProps> = ({ teams, onAdd, onUpdate, onDelete }) => {
  const [isEditing, setIsEditing] = useState<string | null>(null);
  const [form, setForm] = useState<Omit<Team, 'id'>>({ number: '', unit: '' });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (isEditing) {
      onUpdate(isEditing, form);
      setIsEditing(null);
    } else {
      onAdd(form);
    }
    setForm({ number: '', unit: '' });
  };

  const handleEdit = (team: Team) => {
    setIsEditing(team.id);
    setForm({ number: team.number, unit: team.unit });
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      <div className="bg-[#1e293b] p-6 rounded-2xl border border-slate-700 shadow-xl">
        <h3 className="text-lg font-bold mb-6 text-white flex items-center gap-2">
          {isEditing ? <Edit2 size={20} className="text-yellow-500" /> : <Plus size={20} className="text-yellow-500" />}
          {isEditing ? 'Editar Equipe' : 'Cadastrar Nova Equipe'}
        </h3>
        <form onSubmit={handleSubmit} className="grid grid-cols-1 sm:grid-cols-2 gap-4 items-end">
          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Número da Equipe</label>
            <input 
              required
              type="text" 
              value={form.number}
              onChange={e => setForm({...form, number: e.target.value})}
              placeholder="Ex: 102"
              className="w-full bg-[#0f172a] border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-yellow-500 outline-none transition-all"
            />
          </div>
          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Unidade</label>
            <input 
              required
              type="text" 
              value={form.unit}
              onChange={e => setForm({...form, unit: e.target.value})}
              placeholder="Ex: Matriz A"
              className="w-full bg-[#0f172a] border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-yellow-500 outline-none transition-all"
            />
          </div>
          <div className="sm:col-span-2 flex justify-end gap-2 mt-2">
            {isEditing && (
              <button 
                type="button"
                onClick={() => { setIsEditing(null); setForm({ number: '', unit: '' }); }}
                className="flex items-center gap-2 px-6 py-3 rounded-xl font-bold bg-slate-700 text-white hover:bg-slate-600 transition-all"
              >
                <X size={18} /> Cancelar
              </button>
            )}
            <button 
              type="submit"
              className="flex items-center gap-2 px-8 py-3 rounded-xl font-bold bg-yellow-500 text-slate-900 hover:bg-yellow-400 transition-all shadow-lg shadow-yellow-500/20"
            >
              {isEditing ? <Check size={18} /> : <Plus size={18} />}
              {isEditing ? 'Salvar Alterações' : 'Cadastrar Equipe'}
            </button>
          </div>
        </form>
      </div>

      <div className="bg-[#0f172a] rounded-2xl border border-slate-800 overflow-hidden shadow-xl">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-900/50 text-slate-400 text-xs uppercase tracking-wider border-b border-slate-800">
              <th className="px-6 py-4">Número da Equipe</th>
              <th className="px-6 py-4">Unidade</th>
              <th className="px-6 py-4 text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800/50">
            {teams.length === 0 ? (
              <tr>
                <td colSpan={3} className="px-6 py-10 text-center text-slate-500 italic">Nenhuma equipe cadastrada.</td>
              </tr>
            ) : (
              teams.map(team => (
                <tr key={team.id} className="hover:bg-slate-800/30 transition-colors group">
                  <td className="px-6 py-4 font-bold text-white airport-font">EQP {team.number}</td>
                  <td className="px-6 py-4 text-slate-400">{team.unit}</td>
                  <td className="px-6 py-4">
                    <div className="flex justify-end gap-2">
                      <button 
                        onClick={() => handleEdit(team)}
                        className="p-2 text-slate-400 hover:text-yellow-500 hover:bg-yellow-500/10 rounded-lg transition-all"
                      >
                        <Edit2 size={18} />
                      </button>
                      <button 
                        onClick={() => onDelete(team.id)}
                        className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-500/10 rounded-lg transition-all"
                      >
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Plus, Edit2, Trash2, X, Check, Truck } from 'lucide-react';
import { Cargo, Team, CargoStatus } from '../types';

interface CargoManagerProps {
  cargos: Cargo[];
  teams: Team[];
  onAdd: (cargo: Omit<Cargo, 'id' | 'status'>) => void;
  onUpdate: (id: string, cargo: Partial<Cargo>) => void;
  onDelete: (id: string) => void;
}

export const CargoManager: React.FC<CargoManagerProps> = ({ cargos, teams, onAdd, onUpdate, onDelete }) => {
  const [isEditing, setIsEditing] = useState<string | null>(null);
  const [form, setForm] = useState<Omit<Cargo, 'id' | 'status'>>({
    teamId: '',
    integrated: '',
    city: '',
    pickupTime: '',
    birdCount: 0,
    totalLoad: 0,
    unit: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (isEditing) {
      onUpdate(isEditing, form);
      setIsEditing(null);
    } else {
      onAdd(form);
    }
    setForm({
      teamId: '',
      integrated: '',
      city: '',
      pickupTime: '',
      birdCount: 0,
      totalLoad: 0,
      unit: ''
    });
  };

  const handleEdit = (cargo: Cargo) => {
    setIsEditing(cargo.id);
    setForm({
      teamId: cargo.teamId,
      integrated: cargo.integrated,
      city: cargo.city,
      pickupTime: cargo.pickupTime,
      birdCount: cargo.birdCount,
      totalLoad: cargo.totalLoad,
      unit: cargo.unit
    });
  };

  return (
    <div className="max-w-6xl mx-auto space-y-8 pb-12">
      <div className="bg-[#1e293b] p-8 rounded-2xl border border-slate-700 shadow-2xl">
        <h3 className="text-xl font-bold mb-8 text-white flex items-center gap-2">
          <Truck size={24} className="text-yellow-500" />
          {isEditing ? 'Editar Registro de Carga' : 'Lançar Nova Carga'}
        </h3>
        <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Equipe Responsável</label>
            <select 
              required
              value={form.teamId}
              onChange={e => setForm({...form, teamId: e.target.value})}
              className="w-full bg-[#0f172a] border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-yellow-500 outline-none transition-all appearance-none"
            >
              <option value="">Selecione uma equipe...</option>
              {teams.map(t => (
                <option key={t.id} value={t.id}>Equipe {t.number} - {t.unit}</option>
              ))}
            </select>
          </div>

          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Integrado (Parceiro)</label>
            <input 
              required
              type="text" 
              value={form.integrated}
              onChange={e => setForm({...form, integrated: e.target.value})}
              placeholder="Nome do produtor/empresa"
              className="w-full bg-[#0f172a] border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-yellow-500 outline-none transition-all"
            />
          </div>

          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Cidade Destino/Origem</label>
            <input 
              required
              type="text" 
              value={form.city}
              onChange={e => setForm({...form, city: e.target.value})}
              placeholder="Ex: Cascavel - PR"
              className="w-full bg-[#0f172a] border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-yellow-500 outline-none transition-all"
            />
          </div>

          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Hora Apanha</label>
            <input 
