export enum CargoStatus {
  PROGRAMADO = 'PROGRAMADO',
  CARREGANDO = 'CARREGANDO',
  FINALIZADO = 'FINALIZADO'
}

export interface Team {
  id: string;
  number: string;
  unit: string;
}

export interface Cargo {
  id: string;
  teamId: string;
  integrated: string;
  city: string;
  pickupTime: string; // ISO string para data e hora (Hora Apanha)
  birdCount: number;
  totalLoad: number;
  unit: string;
  status: CargoStatus;
  startTime?: string; // HH:mm
  endTime?: string; // HH:mm
  endDate?: string; // DD/MM/YYYY
}

