import React from 'react';
import { Play, CheckCircle, Trash2, Edit2, AlertCircle } from 'lucide-react';
import { Cargo, Team, CargoStatus } from '../types';

interface AirportBoardProps {
  cargos: Cargo[];
  teams: Team[];
  onStart: (id: string) => void;
  onEnd: (id: string) => void;
  onDelete: (id: string) => void;
  onEdit: (cargo: Cargo) => void;
}

export const AirportBoard: React.FC<AirportBoardProps> = ({ cargos, teams, onStart, onEnd, onDelete, onEdit }) => {
  const getTeamLabel = (teamId: string) => {
    const team = teams.find(t => t.id === teamId);
    return team ? `EQP ${team.number}` : '---';
  };

  /**
   * Fix: Updated formatPickupTime to always return an object with date and time properties.
   * This prevents type errors when accessing pickup.time and pickup.date.
   */
  const formatPickupTime = (isoString: string): { date: string; time: string } => {
    if (!isoString) return { date: '---', time: '---' };
    try {
      const date = new Date(isoString);
      if (isNaN(date.getTime())) {
        return { date: '---', time: isoString || '---' };
      }
      return {
        date: date.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' }),
        time: date.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })
      };
    } catch {
      return { date: '---', time: isoString || '---' };
    }
  };

  const getStatusStyle = (status: CargoStatus) => {
    switch (status) {
      case CargoStatus.PROGRAMADO: return 'text-sky-400 bg-sky-400/10 border-sky-400/20';
      case CargoStatus.CARREGANDO: return 'text-yellow-400 bg-yellow-400/10 border-yellow-400/20 status-carregando font-bold';
      case CargoStatus.FINALIZADO: return 'text-emerald-400 bg-emerald-400/10 border-emerald-400/20';
      default: return 'text-slate-400';
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black uppercase tracking-widest text-white airport-font">
