          <p className="text-slate-500 text-xs font-bold mt-1 uppercase tracking-tighter">Acompanhamento de horários de apanha em tempo real</p>
        </div>
        <div className="flex gap-4 p-3 bg-slate-900/50 rounded-xl border border-slate-800">
          <div className="flex items-center gap-1.5 text-[10px] font-bold uppercase text-sky-400">
            <div className="w-2 h-2 rounded-full bg-sky-400"></div> PROGRAMADO
          </div>
          <div className="flex items-center gap-1.5 text-[10px] font-bold uppercase text-yellow-400">
            <div className="w-2 h-2 rounded-full bg-yellow-400 animate-pulse"></div> CARREGANDO
          </div>
          <div className="flex items-center gap-1.5 text-[10px] font-bold uppercase text-emerald-400">
            <div className="w-2 h-2 rounded-full bg-emerald-400"></div> FINALIZADO
          </div>
        </div>
      </div>

      <div className="overflow-x-auto rounded-xl border border-slate-800 shadow-2xl bg-[#020617]">
        <table className="w-full text-left airport-font min-w-[1000px]">
          <thead>
            <tr className="bg-slate-900 text-slate-500 text-[11px] uppercase tracking-widest border-b border-slate-800">
              <th className="px-5 py-4">Status</th>
              <th className="px-5 py-4">Equipe</th>
              <th className="px-5 py-4">Integrado</th>
              <th className="px-5 py-4">Cidade</th>
              <th className="px-5 py-4 text-center">Data/Hora Apanha</th>
              <th className="px-5 py-4 text-center">Aves</th>
              <th className="px-5 py-4 text-center">Peso (Kg)</th>
              <th className="px-5 py-4">Operação</th>
              <th className="px-5 py-4 text-center">Gestão</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800">
            {cargos.length === 0 ? (
              <tr>
                <td colSpan={9} className="px-6 py-20 text-center text-slate-600">
                  <div className="flex flex-col items-center gap-2">
                    <AlertCircle size={40} className="opacity-20" />
                    <span className="uppercase font-bold tracking-widest">Nenhuma carga programada</span>
                  </div>
                </td>
              </tr>
            ) : (
              cargos.map((cargo) => {
                const pickup = formatPickupTime(cargo.pickupTime);
                return (
                  <tr key={cargo.id} className="hover:bg-slate-900/60 transition-colors">
                    <td className="px-5 py-5 whitespace-nowrap">
                      <span className={`px-2.5 py-1 rounded border text-[10px] tracking-widest ${getStatusStyle(cargo.status)}`}>
                        {cargo.status}
                      </span>
                    </td>
                    <td className="px-5 py-5">
                      <div className="text-white font-bold">{getTeamLabel(cargo.teamId)}</div>
                      <div className="text-[10px] text-slate-500 truncate max-w-[100px] uppercase">{cargo.unit}</div>
                    </td>
                    <td className="px-5 py-5 text-slate-300 font-medium uppercase text-sm">{cargo.integrated}</td>
                    <td className="px-5 py-5 text-slate-400 text-sm uppercase">{cargo.city}</td>
                    <td className="px-5 py-5 text-center">
                      <div className="text-yellow-500 font-bold text-lg">{pickup.time}</div>
                      <div className="text-slate-500 text-[10px] font-bold uppercase">{pickup.date}</div>
                    </td>
                    <td className="px-5 py-5 text-center text-slate-300">{cargo.birdCount.toLocaleString()}</td>
                    <td className="px-5 py-5 text-center text-slate-300">{cargo.totalLoad.toLocaleString()}</td>

                    <td className="px-5 py-5">
