                        {cargo.status === CargoStatus.FINALIZADO && (
                          <div className="flex flex-col text-[10px] leading-tight">
                            <span className="text-slate-500 font-bold">INÍCIO: <span className="text-white">{cargo.startTime}</span></span>
                            <span className="text-slate-500 font-bold">FIM: <span className="text-white">{cargo.endTime}</span></span>
                            <span className="text-emerald-500/80 font-bold mt-0.5">{cargo.endDate}</span>
                          </div>
                        )}
                      </div>
                    </td>

                    <td className="px-5 py-5">
                      <div className="flex justify-center gap-1">
                        <button 
                          onClick={() => onEdit(cargo)}
                          className="p-2 text-slate-500 hover:text-yellow-500 hover:bg-yellow-500/10 rounded-lg transition-all"
                          title="Editar"
                        >
                          <Edit2 size={16} />
                        </button>
                        <button 
                          onClick={() => onDelete(cargo.id)}
