                    </td>
                    <td className="px-5 py-5 text-center text-slate-300">{cargo.birdCount.toLocaleString()}</td>
                    <td className="px-5 py-5 text-center text-slate-300">{cargo.totalLoad.toLocaleString()}</td>

                    <td className="px-5 py-5">
                      <div className="flex items-center gap-3">
                        {cargo.status === CargoStatus.PROGRAMADO && (
                          <button 
                            onClick={() => onStart(cargo.id)}
                            className="flex items-center gap-1 px-3 py-1.5 bg-sky-500 text-slate-900 rounded-md font-black text-[10px] uppercase hover:bg-sky-400 transition-all"
                          >
                            <Play size={12} fill="currentColor" /> Início
                          </button>
                        )}
                        {cargo.status === CargoStatus.CARREGANDO && (
                          <button 
                            onClick={() => onEnd(cargo.id)}
                            className="flex items-center gap-1 px-3 py-1.5 bg-emerald-500 text-slate-900 rounded-md font-black text-[10px] uppercase hover:bg-emerald-400 transition-all"
                          >
                            <CheckCircle size={12} /> Fim
                          </button>
                        )}
                        {cargo.status === CargoStatus.FINALIZADO && (
                          <div className="flex flex-col text-[10px] leading-tight">
                            <span className="text-slate-500 font-bold">INÍCIO: <span className="text-white">{cargo.startTime}</span></span>
                            <span className="text-slate-500 font-bold">FIM: <span className="text-white">{cargo.endTime}</span></span>
                            <span className="text-emerald-500/80 font-bold mt-0.5">{cargo.endDate}</span>
                          </div>
                        )}
                      </div>
                    </td>

                    <td className="px-5 py-5">
                      <div className="flex justify-center gap-1">
                        <button 
                          onClick={() => onEdit(cargo)}
                          className="p-2 text-slate-500 hover:text-yellow-500 hover:bg-yellow-500/10 rounded-lg transition-all"
                          title="Editar"
                        >
                          <Edit2 size={16} />
                        </button>
                        <button 
                          onClick={() => onDelete(cargo.id)}
                          className="p-2 text-slate-500 hover:text-red-500 hover:bg-red-500/10 rounded-lg transition-all"
                          title="Excluir Permanentemente"
                        >
                          <Trash2 size={16} />
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

