  cargos: Cargo[];
  teams: Team[];
  units: Unit[];
  onAdd: (cargo: Omit<Cargo, 'id' | 'status'>) => void;
  onBulkAdd: (cargos: Omit<Cargo, 'id' | 'status'>[]) => void;
  onUpdate: (id: string, cargo: Partial<Cargo>) => void;
  onDelete: (id: string) => void;
  onEdit: (cargo: Cargo) => void;
  editingCargo: Cargo | null;
  onCancel: () => void;
}

export const CargoManager: React.FC<CargoManagerProps> = ({ 
  cargos, 
  teams, 
  units,
  onAdd, 
  onBulkAdd,
  onUpdate, 
  onDelete, 
  onEdit,
  editingCargo, 
  onCancel 
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [form, setForm] = useState<Omit<Cargo, 'id' | 'status'>>({
    teamId: '',
    integrated: '',
    city: '',
    pickupTime: '',
    birdCount: 0,
    totalLoad: 0,
    unitId: '',
    unit: ''
  });

  useEffect(() => {
    if (editingCargo) {
      setForm({
        teamId: editingCargo.teamId,
        integrated: editingCargo.integrated,
        city: editingCargo.city,
        pickupTime: editingCargo.pickupTime,
        birdCount: editingCargo.birdCount,
        totalLoad: editingCargo.totalLoad,
        unitId: editingCargo.unitId || '',
        unit: editingCargo.unit
      });
    } else {
      setForm({
        teamId: '',
        integrated: '',
        city: '',
        pickupTime: '',
        birdCount: 0,
        totalLoad: 0,
        unitId: '',
        unit: ''
      });
    }
  }, [editingCargo]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingCargo) {
      onUpdate(editingCargo.id, form);
    } else {
      onAdd(form);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      const lines = text.split('\n');
      const importedCargos: Omit<Cargo, 'id' | 'status'>[] = [];

      for (let i = 1; i < lines.length; i++) {
        const line = lines[i].trim();
        if (!line) continue;

        const values = line.includes(';') ? line.split(';') : line.split(',');

        if (values.length >= 7) {
          const teamNumber = values[0].trim().replace(/[^0-9]/g, '');
          const team = teams.find(t => t.number === teamNumber);
          const unitName = values[6].trim().toUpperCase();
          const unit = units.find(u => u.name.toUpperCase() === unitName);

          if (team) {
            importedCargos.push({
              teamId: team.id,
              integrated: values[1].trim(),
              city: values[2].trim(),
              pickupTime: values[3].trim(),
              birdCount: parseInt(values[4]) || 0,
              totalLoad: parseInt(values[5]) || 0,
              unitId: unit?.id || '',
              unit: unit?.name || values[6].trim()
            });
          }
        }
      }

      if (importedCargos.length > 0) {
        onBulkAdd(importedCargos);
      } else {
        alert("Nenhuma carga válida encontrada. Verifique se as equipes existem.");
      }

      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  const downloadTemplate = () => {
    const header = "Equipe,Integrado,Cidade,Hora Apanha,Numero Aves,Total Carga,Unidade\n";
    const example = "001,Produtor Exemplo,Cidade Exemplo,2024-05-20T08:00,5000,12000,UNIDADE A";
    const blob = new Blob([header + example], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'modelo_importacao_cargas.csv';
    a.click();
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      <div className="bg-[#1e293b] p-8 rounded-2xl border border-slate-700 shadow-2xl">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
          <h3 className="text-xl font-bold text-white flex items-center gap-3 uppercase tracking-widest">
            <Truck size={24} className="text-yellow-500" />
            {editingCargo ? 'Editar Carga' : 'Cadastro de Cargas'}
          </h3>

          <div className="flex gap-2">
            <button 
              onClick={downloadTemplate}
              className="flex items-center gap-2 px-3 py-2 rounded-lg text-[10px] font-black uppercase bg-slate-800 text-slate-400 hover:text-white transition-all border border-slate-700"
              title="Baixar Modelo CSV"
            >
              <Download size={14} /> Modelo
            </button>
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="flex items-center gap-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase bg-sky-600 text-white hover:bg-sky-500 transition-all shadow-lg shadow-sky-600/20"
            >
              <FileUp size={16} /> Importar Planilha
            </button>
            <input 
              type="file" 
              ref={fileInputRef} 
              onChange={handleFileUpload} 
              accept=".csv" 
              className="hidden" 
            />
          </div>
        </div>

        <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Equipe Responsável</label>
            <select 
              required
              value={form.teamId}
              onChange={e => setForm({...form, teamId: e.target.value})}
              className="w-full bg-[#0f172a] border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-yellow-500 outline-none transition-all appearance-none"
            >
              <option value="">Selecione a Equipe...</option>
              {teams.map(t => (
                <option key={t.id} value={t.id}>EQP {t.number} ({t.unit})</option>
              ))}
            </select>
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Integrado (Produtor)</label>
            <input 
              required
              type="text" 
              value={form.integrated}
              onChange={e => setForm({...form, integrated: e.target.value})}
              placeholder="Nome do integrado"
              className="w-full bg-[#0f172a] border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-yellow-500 outline-none transition-all"
            />
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Cidade</label>
            <input 
              required
              type="text" 
              value={form.city}
              onChange={e => setForm({...form, city: e.target.value})}
              placeholder="Cidade de origem/destino"
              className="w-full bg-[#0f172a] border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-yellow-500 outline-none transition-all"
            />
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Data e Hora Apanha</label>
            <input 
              required
              type="datetime-local" 
              value={form.pickupTime}
              onChange={e => setForm({...form, pickupTime: e.target.value})}
              className="w-full bg-[#0f172a] border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-yellow-500 outline-none transition-all font-bold airport-font"
            />
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Número de Aves</label>
            <input 
              required
              type="number" 
              value={form.birdCount || ''}
              onChange={e => setForm({...form, birdCount: parseInt(e.target.value) || 0})}
              placeholder="0"
              className="w-full bg-[#0f172a] border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-yellow-500 outline-none transition-all airport-font"
            />
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Total Carga (Kg)</label>
            <input 
              required
              type="number" 
              value={form.totalLoad || ''}
              onChange={e => setForm({...form, totalLoad: parseInt(e.target.value) || 0})}
              placeholder="0"
              className="w-full bg-[#0f172a] border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-yellow-500 outline-none transition-all airport-font"
            />
          </div>

          <div className="space-y-2 md:col-span-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Unidade</label>
            <select 
              required
              value={form.unitId}
              onChange={e => setForm({...form, unitId: e.target.value})}
              className="w-full bg-[#0f172a] border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-yellow-500 outline-none transition-all appearance-none"
            >
              <option value="">Selecione a Unidade...</option>
              {units.map(u => (
                <option key={u.id} value={u.id}>{u.name}</option>
              ))}
            </select>
          </div>

          <div className="md:col-span-2 flex justify-end gap-3 pt-6 border-t border-slate-700/50 mt-4">
            <button 
              type="button"
              onClick={onCancel}
              className="flex items-center gap-2 px-6 py-3 rounded-xl font-bold bg-slate-700 text-white hover:bg-slate-600 transition-all uppercase text-xs"
            >
              <X size={16} /> Cancelar
            </button>
            <button 
              type="submit"
              className="flex items-center gap-2 px-10 py-3 rounded-xl font-bold bg-yellow-500 text-slate-900 hover:bg-yellow-400 transition-all shadow-lg shadow-yellow-500/20 uppercase text-xs"
            >
              {editingCargo ? <Check size={18} /> : <Plus size={18} />}
              {editingCargo ? 'Salvar Alterações' : 'Cadastrar Carga'}
            </button>
          </div>
        </form>
      </div>

      <div className="bg-[#020617] rounded-2xl border border-slate-800 overflow-hidden shadow-2xl">
        <div className="overflow-x-auto">
          <table className="w-full text-left airport-font">
            <thead>
              <tr className="bg-slate-900/80 text-slate-500 text-[10px] uppercase tracking-widest border-b border-slate-800">
                <th className="px-6 py-4">Equipe</th>
                <th className="px-6 py-4">Integrado</th>
                <th className="px-6 py-4 text-center">Aves/Kg</th>
                <th className="px-6 py-4 text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-800">
              {cargos.length === 0 ? (
                <tr>
                  <td colSpan={4} className="px-6 py-12 text-center text-slate-600 uppercase font-bold text-xs tracking-widest">Nenhuma carga cadastrada</td>
                </tr>
              ) : (
                cargos.map(cargo => {
                  const team = teams.find(t => t.id === cargo.teamId);
                  return (
                    <tr key={cargo.id} className="hover:bg-slate-900/40 transition-colors">
                      <td className="px-6 py-5">
                        <div className="font-bold text-white">EQP {team?.number || '---'}</div>
                        <div className="text-[10px] text-slate-500 uppercase">{cargo.unit}</div>
                      </td>
                      <td className="px-6 py-5">
                        <div className="text-slate-200 font-medium uppercase text-sm">{cargo.integrated}</div>
                        <div className="text-[10px] text-slate-500 uppercase">{cargo.city}</div>
                      </td>
                      <td className="px-6 py-5 text-center">
                        <div className="text-slate-300 text-xs">{cargo.birdCount.toLocaleString()} Aves</div>
                        <div className="text-yellow-500/80 text-[10px] font-bold">{cargo.totalLoad.toLocaleString()} Kg</div>
                      </td>
                      <td className="px-6 py-5">
                        <div className="flex justify-end gap-2">
                          <button 
                            onClick={() => onEdit(cargo)} 
                            className="p-2 text-slate-500 hover:text-yellow-500 hover:bg-yellow-500/10 rounded-lg transition-all"
                            title="Editar"
                          >
                            <Edit2 size={16} />
                          </button>
                          <button 
                            onClick={() => onDelete(cargo.id)}
                            className="p-2 text-slate-500 hover:text-red-500 hover:bg-red-500/10 rounded-lg transition-all"
                            title="Excluir"
                          >
                            <Trash2 size={16} />
                          </button>
                        </div>
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { AirportBoard } from './components/AirportBoard';
import { TeamManager } from './components/TeamManager';
import { CargoManager } from './components/CargoManager';
import { UnitManager } from './components/UnitManager';
import { Team, Cargo, ViewMode, CargoStatus, Unit } from './types';

const generateId = () => {
  try {
    return crypto.randomUUID();
  } catch (e) {
    return Math.random().toString(36).substring(2, 15) + Date.now().toString(36);
  }
};

const App: React.FC = () => {
  const [units, setUnits] = useState<Unit[]>(() => {
    const saved = localStorage.getItem('units_v2');
    return saved ? JSON.parse(saved) : [];
  });

  const [teams, setTeams] = useState<Team[]>(() => {
    const saved = localStorage.getItem('teams_v2');
    return saved ? JSON.parse(saved) : [];
  });

  const [cargos, setCargos] = useState<Cargo[]>(() => {
    const saved = localStorage.getItem('cargos_v2');
    return saved ? JSON.parse(saved) : [];
  });

  const [view, setView] = useState<ViewMode>('DASHBOARD');
  const [editingCargo, setEditingCargo] = useState<Cargo | null>(null);

  useEffect(() => {
    localStorage.setItem('units_v2', JSON.stringify(units));
  }, [units]);

  useEffect(() => {
    localStorage.setItem('teams_v2', JSON.stringify(teams));
  }, [teams]);

  useEffect(() => {
    localStorage.setItem('cargos_v2', JSON.stringify(cargos));
  }, [cargos]);

  // Gestão Global
  const clearAllData = () => {
    if (window.confirm('ATENÇÃO: Isso irá apagar TUDO (Unidades, Equipes e Cargas) permanentemente. Deseja continuar?')) {
      setUnits([]);
      setCargos([]);
      setTeams([]);
      localStorage.removeItem('units_v2');
      localStorage.removeItem('teams_v2');
      localStorage.removeItem('cargos_v2');
      setView('DASHBOARD');
    }
  };

  const clearAllCargos = () => {
    if (window.confirm('Deseja apagar todas as cargas da lista?')) {
      setCargos([]);
      localStorage.removeItem('cargos_v2');
    }
  };

  // Gestão de Unidades
  const addUnit = (unit: Omit<Unit, 'id'>) => {
    setUnits(prev => [...prev, { ...unit, id: generateId() }]);
  };

  const updateUnit = (id: string, updated: Omit<Unit, 'id'>) => {
    setUnits(prev => prev.map(u => u.id === id ? { ...updated, id } : u));
    setTeams(prev => prev.map(t => t.unitId === id ? { ...t, unit: updated.name } : t));
    setCargos(prev => prev.map(c => c.unitId === id ? { ...c, unit: updated.name } : c));
  };

  const deleteUnit = (id: string) => {
    if (window.confirm('Excluir esta unidade? Isso não apagará equipes ou cargas, mas elas ficarão sem unidade vinculada.')) {
      setUnits(prev => prev.filter(u => u.id !== id));
      setTeams(prev => prev.map(t => t.unitId === id ? { ...t, unitId: '', unit: 'N/A' } : t));
      setCargos(prev => prev.map(c => c.unitId === id ? { ...c, unitId: '', unit: 'N/A' } : c));
    }
  };

  // Gestão de Equipes
  const addTeam = (teamData: Omit<Team, 'id'>) => {
    const unit = units.find(u => u.id === teamData.unitId);
    setTeams(prev => [...prev, { ...teamData, unit: unit?.name || 'N/A', id: generateId() }]);
  };

  const updateTeam = (id: string, updated: Omit<Team, 'id'>) => {
    const unit = units.find(u => u.id === updated.unitId);
    setTeams(prev => prev.map(t => t.id === id ? { ...updated, unit: unit?.name || 'N/A', id } : t));
  };

  const deleteTeam = (id: string) => {
    if (window.confirm('Excluir esta equipe e todas as suas cargas associadas?')) {
      setTeams(prev => prev.filter(t => t.id !== id));
      setCargos(prev => prev.filter(c => c.teamId !== id));
    }
  };

  // Gestão de Cargas
  const addCargo = (cargo: Omit<Cargo, 'id' | 'status'>) => {
    const unit = units.find(u => u.id === cargo.unitId);
    setCargos(prev => [...prev, { 
      ...cargo, 
      unit: unit?.name || 'N/A',
      id: generateId(), 
      status: CargoStatus.PROGRAMADO 
    }]);
    setView('DASHBOARD');
  };

  const bulkAddCargos = (newCargos: Omit<Cargo, 'id' | 'status'>[]) => {
    const formatted = newCargos.map(c => {
      const unit = units.find(u => u.id === c.unitId);
      return {
        ...c,
        unit: unit?.name || 'N/A',
        id: generateId(),
        status: CargoStatus.PROGRAMADO
      };
    });
    setCargos(prev => [...prev, ...formatted]);
    setView('DASHBOARD');
    alert(`${formatted.length} cargas importadas com sucesso!`);
  };

  const updateCargo = (id: string, updated: Partial<Cargo>) => {
    const unit = units.find(u => u.id === updated.unitId);
    setCargos(prev => prev.map(c => c.id === id ? { 
      ...c, 
      ...updated, 
      unit: unit ? unit.name : (updated.unit || c.unit) 
    } : c));
    setEditingCargo(null);
    setView('DASHBOARD');
  };

  const deleteCargo = (id: string) => {
    if (window.confirm('Deseja realmente excluir esta carga?')) {
      setCargos(prev => prev.filter(c => c.id !== id));
      if (editingCargo?.id === id) {
        setEditingCargo(null);
      }
    }
  };

  // Operações de Tempo
  const startCargo = (id: string) => {
    const now = new Date();
    const time = now.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
    updateCargo(id, { 
      status: CargoStatus.CARREGANDO, 
      startTime: time 
    });
  };

  const endCargo = (id: string) => {
    const now = new Date();
    const time = now.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
    const date = now.toLocaleDateString('pt-BR');
    updateCargo(id, { 
      status: CargoStatus.FINALIZADO, 
      endTime: time,
      endDate: date
    });
  };

  const handleEditCargo = (cargo: Cargo) => {
    setEditingCargo(cargo);
    setView('CARGO_ENTRY');
  };

  return (
    <Layout 
      view={view} 
      setView={setView} 
      onReset={clearAllData} 
      units={units}
    >
      {view === 'DASHBOARD' && (
        <AirportBoard 
          cargos={cargos} 
          teams={teams} 
          onStart={startCargo} 
          onEnd={endCargo}
          onDelete={deleteCargo}
          onEdit={handleEditCargo}
          onClearAll={clearAllCargos}
        />
      )}
      {view === 'UNITS' && (
        <UnitManager 
          units={units} 
          onAdd={addUnit} 
          onUpdate={updateUnit} 
          onDelete={deleteUnit} 
        />
      )}
      {view === 'TEAMS' && (
        <TeamManager 
          teams={teams} 
          units={units}
          onAdd={addTeam} 
          onUpdate={updateTeam} 
          onDelete={deleteTeam} 
        />
      )}
      {view === 'CARGO_ENTRY' && (
        <CargoManager 
          cargos={cargos} 
          teams={teams} 
          units={units}
          onAdd={addCargo} 
          onBulkAdd={bulkAddCargos}
          onUpdate={updateCargo} 
          onDelete={deleteCargo}
          onEdit={handleEditCargo}
          editingCargo={editingCargo}
          onCancel={() => { setEditingCargo(null); setView('DASHBOARD'); }}
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
