export enum CargoStatus {
  PROGRAMADO = 'PROGRAMADO',
  CARREGANDO = 'CARREGANDO',
  FINALIZADO = 'FINALIZADO',
  ATRASADO = 'ATRASADO'
}

export interface Unit {
  id: string;
  name: string;
}

export interface Team {
  id: string;
  number: string;
  unitId: string; // Agora referenciando a unidade pelo ID
  unit: string;   // Mantido para compatibilidade visual rápida se necessário
}

export interface Cargo {
  id: string;
  teamId: string;
  integrated: string;
  city: string;
  pickupTime: string; 
  birdCount: number;
  totalLoad: number;
  unitId: string;    // Agora referenciando a unidade pelo ID
  unit: string;      // Mantido para compatibilidade
  status: CargoStatus;
  startTime?: string; 
  endTime?: string; 
  endDate?: string; 
}

