                            onClick={() => onStart(cargo.id)}
                            className={`flex items-center gap-1 px-3 py-1.5 rounded-md font-black text-[10px] uppercase transition-all shadow-lg ${
                              isDelayed 
                              ? 'bg-white text-red-600 hover:bg-slate-100 animate-bounce' 
                              : 'bg-sky-500 text-slate-900 hover:bg-sky-400'
                            }`}
                          >
                            <Play size={12} fill="currentColor" /> Início
                          </button>
                        )}
                        {cargo.status === CargoStatus.CARREGANDO && (
                          <button 
                            onClick={() => onEnd(cargo.id)}
                            className="flex items-center gap-1 px-3 py-1.5 bg-emerald-500 text-slate-900 rounded-md font-black text-[10px] uppercase hover:bg-emerald-400 transition-all shadow-lg animate-pulse"
                          >
                            <CheckCircle size={12} /> Fim
                          </button>
                        )}
                        {cargo.status === CargoStatus.FINALIZADO && (
                          <div className="flex flex-col text-[10px] leading-tight">
                            <span className="text-slate-500 font-bold">INÍCIO: <span className="text-white">{cargo.startTime}</span></span>
                            <span className="text-slate-500 font-bold">FIM: <span className="text-white">{cargo.endTime}</span></span>
                            <span className="text-emerald-500/80 font-bold mt-0.5">{cargo.endDate}</span>
                          </div>
                        )}
                      </div>
                    </td>

                    <td className="px-5 py-5">
                      <div className="flex justify-center gap-1">
                        <button 
                          onClick={() => onEdit(cargo)}
                          className={`p-2 rounded-lg transition-all ${isDelayed || isLoading ? 'text-white hover:bg-white/20' : 'text-slate-500 hover:text-yellow-500 hover:bg-yellow-500/10'}`}
                          title="Editar"
                        >
                          <Edit2 size={16} />
                        </button>
                        <button 
                          onClick={() => onDelete(cargo.id)}
                          className={`p-2 rounded-lg transition-all ${isDelayed || isLoading ? 'text-white hover:bg-white/20' : 'text-slate-500 hover:text-red-500 hover:bg-red-500/10'}`}
                          title="Excluir Permanentemente"
                        >
                          <Trash2 size={16} />
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Play, CheckCircle, Trash2, Edit2, AlertCircle, ListX, Clock, Calendar, Zap, Bird } from 'lucide-react';
import { Cargo, Team, CargoStatus } from '../types';

interface AirportBoardProps {
  cargos: Cargo[];
  teams: Team[];
  onStart: (id: string) => void;
  onEnd: (id: string) => void;
  onDelete: (id: string) => void;
  onEdit: (cargo: Cargo) => void;
  onClearAll: () => void;
}

export const AirportBoard: React.FC<AirportBoardProps> = ({ 
  cargos, 
  teams, 
  onStart, 
  onEnd, 
  onDelete, 
  onEdit,
  onClearAll
}) => {
  const [now, setNow] = useState(new Date());

  // Atualiza o "agora" a cada 10 segundos para garantir que o status de atraso seja preciso
  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 10000);
    return () => clearInterval(timer);
  }, []);

  const getTeamLabel = (teamId: string) => {
    const team = teams.find(t => t.id === teamId);
    return team ? `EQP ${team.number}` : '---';
  };

  const getEffectiveStatus = (cargo: Cargo): CargoStatus => {
    if (cargo.status === CargoStatus.PROGRAMADO) {
      const scheduledDate = new Date(cargo.pickupTime);
      if (now > scheduledDate) {
        return CargoStatus.ATRASADO;
      }
    }
    return cargo.status;
  };

  const formatPickupTime = (isoString: string): { date: string; time: string; isPast: boolean } => {
    if (!isoString) return { date: '---', time: '---', isPast: false };
    try {
      const scheduledDate = new Date(isoString);
      if (isNaN(scheduledDate.getTime())) {
        return { date: '---', time: isoString || '---', isPast: false };
      }
      return {
        date: scheduledDate.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' }),
        time: scheduledDate.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
        isPast: now > scheduledDate
      };
    } catch {
      return { date: '---', time: isoString || '---', isPast: false };
    }
  };

  const getStatusStyle = (status: CargoStatus) => {
    switch (status) {
      case CargoStatus.PROGRAMADO: return 'text-sky-400 bg-sky-400/10 border-sky-400/20';
      case CargoStatus.CARREGANDO: return 'text-slate-900 bg-yellow-400 border-yellow-500 font-black shadow-[0_0_10px_rgba(234,179,8,0.5)]';
      case CargoStatus.FINALIZADO: return 'text-emerald-400 bg-emerald-400/10 border-emerald-400/20';
      case CargoStatus.ATRASADO: return 'text-red-500 bg-red-600 text-white border-red-400 font-black';
      default: return 'text-slate-400';
    }
  };

  // Cálculos de Resumo com soma de aves
  const stats = cargos.reduce((acc, cargo) => {
    const status = getEffectiveStatus(cargo);
    const birds = cargo.birdCount || 0;

    if (status === CargoStatus.FINALIZADO) {
      acc.finalizado++;
      acc.avesFinalizado += birds;
    } else if (status === CargoStatus.CARREGANDO) {
      acc.carregando++;
      acc.avesCarregando += birds;
    } else if (status === CargoStatus.PROGRAMADO || status === CargoStatus.ATRASADO) {
      acc.programadoAtrasado++;
      acc.avesProgramadoAtrasado += birds;
      if (status === CargoStatus.ATRASADO) {
        acc.apenasAtrasado++;
      }
    }
    return acc;
  }, { 
    finalizado: 0, avesFinalizado: 0,
    carregando: 0, avesCarregando: 0,
    programadoAtrasado: 0, avesProgramadoAtrasado: 0,
    apenasAtrasado: 0 
  });

  return (
    <div className="space-y-6">
      {/* Header e Título */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black uppercase tracking-widest text-white airport-font">
            PAINEL DE <span className="text-yellow-500 underline decoration-yellow-500/30">LOGÍSTICA</span>
          </h2>
          <div className="flex items-center gap-4 mt-1">
            <p className="text-slate-500 text-xs font-bold uppercase tracking-tighter">Acompanhamento em tempo real</p>
            {cargos.length > 0 && (
              <button 
                onClick={onClearAll}
                className="flex items-center gap-1.5 text-[10px] font-black text-red-500 hover:text-red-400 transition-colors uppercase bg-red-500/10 px-2 py-1 rounded"
              >
                <ListX size={12} /> Limpar Todas as Cargas
              </button>
            )}
          </div>
        </div>

        <div className="flex flex-wrap gap-4 p-3 bg-slate-900/50 rounded-xl border border-slate-800">
          <div className="flex items-center gap-1.5 text-[10px] font-bold uppercase text-sky-400">
            <div className="w-2 h-2 rounded-full bg-sky-400"></div> PROGRAMADO
          </div>
          <div className="flex items-center gap-1.5 text-[10px] font-bold uppercase text-red-500">
            <div className="w-2 h-2 rounded-full bg-red-500 animate-ping"></div> ATRASADO
          </div>
          <div className="flex items-center gap-1.5 text-[10px] font-bold uppercase text-yellow-400">
            <div className="w-2 h-2 rounded-full bg-yellow-400 animate-pulse"></div> CARREGANDO
          </div>
          <div className="flex items-center gap-1.5 text-[10px] font-bold uppercase text-emerald-400">
            <div className="w-2 h-2 rounded-full bg-emerald-400"></div> FINALIZADO
          </div>
        </div>
      </div>

      {/* Cartões de Resumo (Somas) */}
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
        {/* Soma Finalizado */}
        <div className="bg-[#0f172a] border border-emerald-500/30 rounded-2xl p-5 shadow-lg relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
            <CheckCircle size={64} className="text-emerald-500" />
          </div>
          <p className="text-[10px] font-black uppercase text-emerald-500/70 tracking-widest mb-1">Cargas Finalizadas</p>
          <div className="flex flex-col gap-1">
            <div className="flex items-baseline gap-3">
              <span className="text-4xl font-black text-white airport-font">{stats.finalizado}</span>
              <span className="text-[10px] font-bold text-slate-500 uppercase">Viagens</span>
            </div>
            <div className="flex items-center gap-2 text-emerald-400 font-bold text-sm">
              <Bird size={14} />
              <span className="airport-font uppercase">{stats.avesFinalizado.toLocaleString()} Aves</span>
            </div>
          </div>
          <div className="mt-4 w-full bg-emerald-500/10 h-1.5 rounded-full overflow-hidden">
            <div className="bg-emerald-500 h-full transition-all duration-1000" style={{ width: cargos.length ? `${(stats.finalizado / cargos.length) * 100}%` : '0%' }} />
          </div>
        </div>

        {/* Soma Carregando */}
        <div className="bg-[#0f172a] border border-yellow-500/30 rounded-2xl p-5 shadow-lg relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
            <Zap size={64} className="text-yellow-500" />
          </div>
          <p className="text-[10px] font-black uppercase text-yellow-500/70 tracking-widest mb-1">Em Carregamento</p>
          <div className="flex flex-col gap-1">
            <div className="flex items-baseline gap-3">
              <span className="text-4xl font-black text-white airport-font">{stats.carregando}</span>
              <span className="text-[10px] font-bold text-slate-500 uppercase">Ativas</span>
            </div>
            <div className="flex items-center gap-2 text-yellow-500 font-bold text-sm">
              <Bird size={14} />
              <span className="airport-font uppercase">{stats.avesCarregando.toLocaleString()} Aves</span>
            </div>
          </div>
          <div className="mt-4 w-full bg-yellow-500/10 h-1.5 rounded-full overflow-hidden">
            <div className="bg-yellow-500 h-full animate-pulse" style={{ width: cargos.length ? `${(stats.carregando / cargos.length) * 100}%` : '0%' }} />
          </div>
        </div>

        {/* Soma Programado + Atrasado */}
        <div className={`rounded-2xl p-5 shadow-lg relative overflow-hidden group border transition-all ${stats.apenasAtrasado > 0 ? 'bg-red-500/5 border-red-500/30' : 'bg-[#0f172a] border-sky-500/30'}`}>
          <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
            <Calendar size={64} className={stats.apenasAtrasado > 0 ? 'text-red-500' : 'text-sky-500'} />
          </div>
          <p className={`text-[10px] font-black uppercase tracking-widest mb-1 ${stats.apenasAtrasado > 0 ? 'text-red-500/70' : 'text-sky-500/70'}`}>Pendentes & Atrasadas</p>
          <div className="flex flex-col gap-1">
            <div className="flex items-baseline gap-3">
              <span className="text-4xl font-black text-white airport-font">{stats.programadoAtrasado}</span>
              <div className="flex flex-col">
                <span className="text-[10px] font-bold text-slate-500 uppercase leading-none">Total</span>
                {stats.apenasAtrasado > 0 && (
                  <span className="text-[10px] font-black text-red-500 uppercase mt-1 animate-pulse">
                     {stats.apenasAtrasado} Atrasadas
                  </span>
                )}
              </div>
            </div>
            <div className={`flex items-center gap-2 font-bold text-sm ${stats.apenasAtrasado > 0 ? 'text-red-500' : 'text-sky-400'}`}>
              <Bird size={14} />
              <span className="airport-font uppercase">{stats.avesProgramadoAtrasado.toLocaleString()} Aves</span>
            </div>
          </div>
          <div className="mt-4 w-full bg-slate-800 h-1.5 rounded-full overflow-hidden">
            <div className={`${stats.apenasAtrasado > 0 ? 'bg-red-500' : 'bg-sky-500'} h-full transition-all duration-1000`} style={{ width: cargos.length ? `${(stats.programadoAtrasado / cargos.length) * 100}%` : '0%' }} />
          </div>
        </div>
      </div>

      {/* Tabela de Cargas */}
      <div className="overflow-x-auto rounded-xl border border-slate-800 shadow-2xl bg-[#020617]">
        <table className="w-full text-left airport-font min-w-[1000px]">
          <thead>
            <tr className="bg-slate-900 text-slate-500 text-[11px] uppercase tracking-widest border-b border-slate-800">
              <th className="px-5 py-4">Status</th>
              <th className="px-5 py-4">Equipe</th>
              <th className="px-5 py-4">Integrado</th>
              <th className="px-5 py-4">Cidade</th>
              <th className="px-5 py-4 text-center">Data/Hora Apanha</th>
              <th className="px-5 py-4 text-center">Aves</th>
              <th className="px-5 py-4 text-center">Peso (Kg)</th>
              <th className="px-5 py-4">Operação</th>
              <th className="px-5 py-4 text-center">Gestão</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800">
            {cargos.length === 0 ? (
              <tr>
                <td colSpan={9} className="px-6 py-20 text-center text-slate-600">
                  <div className="flex flex-col items-center gap-2">
                    <AlertCircle size={40} className="opacity-20" />
                    <span className="uppercase font-bold tracking-widest">Nenhuma carga programada</span>
                  </div>
                </td>
              </tr>
            ) : (
              cargos.map((cargo) => {
                const pickup = formatPickupTime(cargo.pickupTime);
                const effectiveStatus = getEffectiveStatus(cargo);
                const isDelayed = effectiveStatus === CargoStatus.ATRASADO;
                const isLoading = effectiveStatus === CargoStatus.CARREGANDO;

                return (
                  <tr key={cargo.id} className={`hover:bg-slate-900/60 transition-colors ${isDelayed ? 'row-atrasado-blink' : ''} ${isLoading ? 'row-carregando-blink' : ''}`}>
                    <td className="px-5 py-5 whitespace-nowrap">
                      <span className={`px-2.5 py-1 rounded border text-[10px] tracking-widest shadow-sm ${getStatusStyle(effectiveStatus)}`}>
                        {effectiveStatus}
                      </span>
                    </td>
                    <td className="px-5 py-5">
                      <div className={`font-bold ${isDelayed || isLoading ? 'text-white' : 'text-white'}`}>{getTeamLabel(cargo.teamId)}</div>
                      <div className={`text-[10px] truncate max-w-[100px] uppercase font-bold ${isDelayed || isLoading ? 'text-white' : 'text-slate-500'}`}>{cargo.unit}</div>
                    </td>
                    <td className={`px-5 py-5 font-bold uppercase text-sm ${isDelayed || isLoading ? 'text-white' : 'text-slate-300'}`}>{cargo.integrated}</td>
                    <td className={`px-5 py-5 text-sm uppercase font-medium ${isDelayed || isLoading ? 'text-white' : 'text-slate-400'}`}>{cargo.city}</td>
                    <td className="px-5 py-5 text-center">
                      <div className={`font-black text-xl ${isDelayed || isLoading ? 'text-white drop-shadow-[0_0_8px_rgba(255,255,255,0.5)]' : 'text-yellow-500'}`}>
                        {pickup.time}
                      </div>
                      <div className={`text-[10px] font-bold uppercase ${isDelayed || isLoading ? 'text-white' : 'text-slate-500'}`}>{pickup.date}</div>
                    </td>
                    <td className={`px-5 py-5 text-center font-bold ${isDelayed || isLoading ? 'text-white' : 'text-slate-300'}`}>{cargo.birdCount.toLocaleString()}</td>
                    <td className={`px-5 py-5 text-center font-bold ${isDelayed || isLoading ? 'text-white' : 'text-slate-300'}`}>{cargo.totalLoad.toLocaleString()}</td>

                    <td className="px-5 py-5">
                      <div className="flex items-center gap-3">
                        {(cargo.status === CargoStatus.PROGRAMADO) && (
                          <button 
                            onClick={() => onStart(cargo.id)}
                            className={`flex items-center gap-1 px-3 py-1.5 rounded-md font-black text-[10px] uppercase transition-all shadow-lg ${
                              isDelayed 
                              ? 'bg-white text-red-600 hover:bg-slate-100 animate-bounce' 
                              : 'bg-sky-500 text-slate-900 hover:bg-sky-400'
                            }`}
                          >
                            <Play size={12} fill="currentColor" /> Início
                          </button>
                        )}
                        {cargo.status === CargoStatus.CARREGANDO && (
                          <button 
                            onClick={() => onEnd(cargo.id)}
                            className="flex items-center gap-1 px-3 py-1.5 bg-emerald-500 text-slate-900 rounded-md font-black text-[10px] uppercase hover:bg-emerald-400 transition-all shadow-lg animate-pulse"
                          >
                            <CheckCircle size={12} /> Fim
                          </button>
                        )}
                        {cargo.status === CargoStatus.FINALIZADO && (
                          <div className="flex flex-col text-[10px] leading-tight">
                            <span className="text-slate-500 font-bold">INÍCIO: <span className="text-white">{cargo.startTime}</span></span>
                            <span className="text-slate-500 font-bold">FIM: <span className="text-white">{cargo.endTime}</span></span>
                            <span className="text-emerald-500/80 font-bold mt-0.5">{cargo.endDate}</span>
                          </div>
                        )}
                      </div>
                    </td>

                    <td className="px-5 py-5">
                      <div className="flex justify-center gap-1">
                        <button 
                          onClick={() => onEdit(cargo)}
                          className={`p-2 rounded-lg transition-all ${isDelayed || isLoading ? 'text-white hover:bg-white/20' : 'text-slate-500 hover:text-yellow-500 hover:bg-yellow-500/10'}`}
                          title="Editar"
                        >
                          <Edit2 size={16} />
                        </button>
                        <button 
                          onClick={() => onDelete(cargo.id)}
                          className={`p-2 rounded-lg transition-all ${isDelayed || isLoading ? 'text-white hover:bg-white/20' : 'text-slate-500 hover:text-red-500 hover:bg-red-500/10'}`}
                          title="Excluir Permanentemente"
                        >
                          <Trash2 size={16} />
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, 
  Users, 
  Truck, 
  Clock, 
  RefreshCcw, 
  Building2, 
