import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { AirportBoard } from './components/AirportBoard';
import { TeamManager } from './components/TeamManager';
import { CargoManager } from './components/CargoManager';
import { UnitManager } from './components/UnitManager';
import { SyncView } from './components/SyncView';
import { Team, Cargo, ViewMode, CargoStatus, Unit } from './types';

const generateId = () => {
  try {
    return crypto.randomUUID();
  } catch (e) {
    return Math.random().toString(36).substring(2, 15) + Date.now().toString(36);
  }
};

const App: React.FC = () => {
  const [units, setUnits] = useState<Unit[]>(() => {
    const saved = localStorage.getItem('units_v2');
    return saved ? JSON.parse(saved) : [];
  });

  const [teams, setTeams] = useState<Team[]>(() => {
    const saved = localStorage.getItem('teams_v2');
    return saved ? JSON.parse(saved) : [];
  });

  const [cargos, setCargos] = useState<Cargo[]>(() => {
    const saved = localStorage.getItem('cargos_v2');
    return saved ? JSON.parse(saved) : [];
  });

  const [view, setView] = useState<ViewMode>('DASHBOARD');
  const [editingCargo, setEditingCargo] = useState<Cargo | null>(null);

  useEffect(() => {
    localStorage.setItem('units_v2', JSON.stringify(units));
  }, [units]);

  useEffect(() => {
    localStorage.setItem('teams_v2', JSON.stringify(teams));
  }, [teams]);

  useEffect(() => {
    localStorage.setItem('cargos_v2', JSON.stringify(cargos));
  }, [cargos]);

  // Gestão de Sincronização
  const handleImportSync = (data: { units: Unit[], teams: Team[], cargos: Cargo[] }) => {
    setUnits(data.units);
    setTeams(data.teams);
    setCargos(data.cargos);
    setView('DASHBOARD');
  };

  // Gestão Global
  const clearAllData = () => {
    if (window.confirm('ATENÇÃO: Isso irá apagar TUDO (Unidades, Equipes e Cargas) permanentemente. Deseja continuar?')) {
      setUnits([]);
      setCargos([]);
      setTeams([]);
      localStorage.removeItem('units_v2');
      localStorage.removeItem('teams_v2');
      localStorage.removeItem('cargos_v2');
      setView('DASHBOARD');
    }
  };

  const clearAllCargos = () => {
    if (window.confirm('Deseja apagar todas as cargas da lista?')) {
      setCargos([]);
      localStorage.removeItem('cargos_v2');
    }
  };

  // Gestão de Unidades
  const addUnit = (unit: Omit<Unit, 'id'>) => {
    setUnits(prev => [...prev, { ...unit, id: generateId() }]);
  };

  const updateUnit = (id: string, updated: Omit<Unit, 'id'>) => {
    setUnits(prev => prev.map(u => u.id === id ? { ...updated, id } : u));
    setTeams(prev => prev.map(t => t.unitId === id ? { ...t, unit: updated.name } : t));
    setCargos(prev => prev.map(c => c.unitId === id ? { ...c, unit: updated.name } : c));
  };

  const deleteUnit = (id: string) => {
    if (window.confirm('Excluir esta unidade? Isso não apagará equipes ou cargas, mas elas ficarão sem unidade vinculada.')) {
      setUnits(prev => prev.filter(u => u.id !== id));
      setTeams(prev => prev.map(t => t.unitId === id ? { ...t, unitId: '', unit: 'N/A' } : t));
      setCargos(prev => prev.map(c => c.unitId === id ? { ...c, unitId: '', unit: 'N/A' } : c));
    }
  };

  // Gestão de Equipes
  const addTeam = (teamData: Omit<Team, 'id'>) => {
    const unit = units.find(u => u.id === teamData.unitId);
    setTeams(prev => [...prev, { ...teamData, unit: unit?.name || 'N/A', id: generateId() }]);
  };

  const updateTeam = (id: string, updated: Omit<Team, 'id'>) => {
    const unit = units.find(u => u.id === updated.unitId);
    setTeams(prev => prev.map(t => t.id === id ? { ...updated, unit: unit?.name || 'N/A', id } : t));
  };

  const deleteTeam = (id: string) => {
    if (window.confirm('Excluir esta equipe e todas as suas cargas associadas?')) {
      setTeams(prev => prev.filter(t => t.id !== id));
      setCargos(prev => prev.filter(c => c.teamId !== id));
    }
  };

  // Gestão de Cargas
  const addCargo = (cargo: Omit<Cargo, 'id' | 'status'>) => {
    const unit = units.find(u => u.id === cargo.unitId);
    setCargos(prev => [...prev, { 
      ...cargo, 
      unit: unit?.name || 'N/A',
      id: generateId(), 
      status: CargoStatus.PROGRAMADO 
    }]);
    setView('DASHBOARD');
  };

  const bulkAddCargos = (newCargos: Omit<Cargo, 'id' | 'status'>[]) => {
    const formatted = newCargos.map(c => {
      const unit = units.find(u => u.id === c.unitId);
      return {
        ...c,
        unit: unit?.name || 'N/A',
        id: generateId(),
        status: CargoStatus.PROGRAMADO
      };
    });
    setCargos(prev => [...prev, ...formatted]);
    setView('DASHBOARD');
    alert(`${formatted.length} cargas importadas com sucesso!`);
  };

  const updateCargo = (id: string, updated: Partial<Cargo>) => {
    const unit = units.find(u => u.id === updated.unitId);
    setCargos(prev => prev.map(c => c.id === id ? { 
      ...c, 
      ...updated, 
      unit: unit ? unit.name : (updated.unit || c.unit) 
    } : c));
    setEditingCargo(null);
    setView('DASHBOARD');
  };

  const deleteCargo = (id: string) => {
    if (window.confirm('Deseja realmente excluir esta carga?')) {
      setCargos(prev => prev.filter(c => c.id !== id));
      if (editingCargo?.id === id) {
        setEditingCargo(null);
      }
    }
  };

  // Operações de Tempo
  const startCargo = (id: string) => {
    const now = new Date();
    const time = now.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
    updateCargo(id, { 
      status: CargoStatus.CARREGANDO, 
      startTime: time 
    });
  };

  const endCargo = (id: string) => {
    const now = new Date();
    const time = now.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
    const date = now.toLocaleDateString('pt-BR');
    updateCargo(id, { 
      status: CargoStatus.FINALIZADO, 
      endTime: time,
      endDate: date
    });
  };

  const handleEditCargo = (cargo: Cargo) => {
    setEditingCargo(cargo);
    setView('CARGO_ENTRY');
  };

  return (
    <Layout 
      view={view} 
      setView={setView} 
      onReset={clearAllData} 
      units={units}
    >
      {view === 'DASHBOARD' && (
        <AirportBoard 
          cargos={cargos} 
          teams={teams} 
          onStart={startCargo} 
          onEnd={endCargo}
          onDelete={deleteCargo}
          onEdit={handleEditCargo}
          onClearAll={clearAllCargos}
        />
      )}
      {view === 'UNITS' && (
        <UnitManager 
          units={units} 
          onAdd={addUnit} 
          onUpdate={updateUnit} 
          onDelete={deleteUnit} 
        />
      )}
      {view === 'TEAMS' && (
        <TeamManager 
          teams={teams} 
          units={units}
          onAdd={addTeam} 
          onUpdate={updateTeam} 
          onDelete={deleteTeam} 
        />
      )}
      {view === 'CARGO_ENTRY' && (
        <CargoManager 
          cargos={cargos} 
          teams={teams} 
          units={units}
          onAdd={addCargo} 
          onBulkAdd={bulkAddCargos}
          onUpdate={updateCargo} 
          onDelete={deleteCargo}
          onEdit={handleEditCargo}
          editingCargo={editingCargo}
          onCancel={() => { setEditingCargo(null); setView('DASHBOARD'); }}
        />
      )}
      {view === 'SYNC' && (
        <SyncView 
          units={units}
          teams={teams}
          cargos={cargos}
          onImport={handleImportSync}
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { Cloud, Copy, Download, Upload, CheckCircle2, AlertTriangle, ShieldCheck, Smartphone, Monitor, Trash2, RefreshCcw } from 'lucide-react';
import { Unit, Team, Cargo } from '../types';

interface SyncViewProps {
  units: Unit[];
  teams: Team[];
  cargos: Cargo[];
  onImport: (data: { units: Unit[], teams: Team[], cargos: Cargo[] }) => void;
  onClearCargos: () => void;
  onClearAll: () => void;
}

export const SyncView: React.FC<SyncViewProps> = ({ units, teams, cargos, onImport, onClearCargos, onClearAll }) => {
  const [syncCode, setSyncCode] = useState('');
  const [inputCode, setInputCode] = useState('');
  const [status, setStatus] = useState<'idle' | 'success' | 'error'>('idle');

  const generateSyncCode = () => {
    const data = { units, teams, cargos, timestamp: Date.now() };
    const jsonString = JSON.stringify(data);
    const base64 = btoa(encodeURIComponent(jsonString));
    setSyncCode(base64);
    setStatus('success');
    setTimeout(() => setStatus('idle'), 3000);
  };

  const handleImport = () => {
    try {
      const jsonString = decodeURIComponent(atob(inputCode));
      const data = JSON.parse(jsonString);

      if (data.units && data.teams && data.cargos) {
        if (window.confirm("Isso irá substituir todos os dados atuais no seu celular pelos dados deste código. Continuar?")) {
          onImport(data);
          setInputCode('');
          setStatus('success');
          alert("Sincronização concluída com sucesso!");
        }
      } else {
        throw new Error("Formato inválido");
      }
    } catch (e) {
      alert("Código de sincronização inválido. Verifique se copiou o código completo.");
      setStatus('error');
    }
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(syncCode);
    alert("Código copiado! Agora cole no seu celular.");
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Header Visual */}
      <div className="text-center space-y-4 py-6">
        <div className="inline-flex p-4 bg-yellow-500/10 rounded-full border border-yellow-500/20 shadow-[0_0_30px_rgba(234,179,8,0.1)]">
          <Cloud size={48} className="text-yellow-500 animate-pulse" />
        </div>
        <h2 className="text-3xl font-black uppercase tracking-tighter text-white airport-font">Gestão de <span className="text-yellow-500">Dados</span></h2>
        <p className="text-slate-500 text-sm max-w-lg mx-auto font-medium">Transfira informações entre dispositivos ou realize a manutenção da sua base de dados local.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Exportar (Web -> Mobile) */}
        <div className="bg-[#1e293b] rounded-2xl p-8 border border-slate-700 shadow-xl space-y-6 flex flex-col">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-sky-500/10 rounded-lg text-sky-500">
              <Upload size={20} />
            </div>
            <h3 className="text-lg font-black uppercase tracking-widest text-white">Exportar Dados</h3>
          </div>

          <div className="flex-1 space-y-4">
            <p className="text-xs text-slate-400 leading-relaxed uppercase font-bold tracking-wider">Gere um código seguro para levar seus dados para o celular.</p>

            <div className="bg-slate-900/50 p-4 rounded-xl border border-slate-800">
              <div className="flex items-center justify-between text-[10px] font-black text-slate-500 uppercase mb-2">
                <span>Resumo do Pacote</span>
                <span className="text-sky-400">Pronto</span>
              </div>
              <div className="grid grid-cols-3 gap-2 text-center">
                <div className="p-2 bg-slate-950 rounded-lg border border-slate-800">
                  <div className="text-lg font-black text-white airport-font">{units.length}</div>
                  <div className="text-[8px] text-slate-500 uppercase font-black">Unidades</div>
                </div>
                <div className="p-2 bg-slate-950 rounded-lg border border-slate-800">
                  <div className="text-lg font-black text-white airport-font">{teams.length}</div>
                  <div className="text-[8px] text-slate-500 uppercase font-black">Equipes</div>
                </div>
                <div className="p-2 bg-slate-950 rounded-lg border border-slate-800">
                  <div className="text-lg font-black text-white airport-font">{cargos.length}</div>
                  <div className="text-[8px] text-slate-500 uppercase font-black">Cargas</div>
                </div>
              </div>
            </div>

            {syncCode && (
              <div className="space-y-2 animate-in zoom-in-95 duration-300">
                <label className="text-[10px] font-black text-yellow-500 uppercase tracking-widest block">Código Gerado</label>
                <div className="relative">
                  <textarea 
                    readOnly
                    value={syncCode}
                    className="w-full bg-slate-950 border border-slate-800 rounded-xl p-3 text-[10px] text-slate-500 airport-font h-24 resize-none focus:outline-none"
                  />
                  <button 
                    onClick={copyToClipboard}
                    className="absolute bottom-3 right-3 p-2 bg-yellow-500 text-slate-900 rounded-lg hover:scale-105 active:scale-95 transition-all shadow-lg"
                  >
                    <Copy size={16} />
                  </button>
                </div>
              </div>
            )}
          </div>

          <button 
            onClick={generateSyncCode}
            className="w-full py-4 bg-sky-600 hover:bg-sky-500 text-white rounded-xl font-black uppercase text-xs tracking-[0.2em] transition-all flex items-center justify-center gap-2 shadow-lg shadow-sky-600/20"
          >
            {status === 'success' ? <CheckCircle2 size={18} /> : <Monitor size={18} />}
            Gerar Código Único
          </button>
        </div>

        {/* Importar (Mobile -> Web ou vice-versa) */}
        <div className="bg-[#1e293b] rounded-2xl p-8 border border-slate-700 shadow-xl space-y-6 flex flex-col">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-emerald-500/10 rounded-lg text-emerald-500">
              <Download size={20} />
            </div>
            <h3 className="text-lg font-black uppercase tracking-widest text-white">Importar Dados</h3>
          </div>

          <div className="flex-1 space-y-4">
