            <div className="space-y-2">
              <label className="text-[10px] font-black text-emerald-500 uppercase tracking-widest block">Colar Código Aqui</label>
              <textarea 
                value={inputCode}
                onChange={(e) => setInputCode(e.target.value)}
                placeholder="Cole o código Base64 aqui..."
                className="w-full bg-slate-950 border border-slate-800 rounded-xl p-4 text-[10px] text-slate-300 airport-font h-40 resize-none focus:ring-2 focus:ring-emerald-500 outline-none transition-all placeholder:text-slate-700"
              />
            </div>

            <div className="flex items-start gap-3 p-3 bg-red-500/5 rounded-xl border border-red-500/20">
              <AlertTriangle size={16} className="text-red-500 shrink-0 mt-0.5" />
              <p className="text-[9px] text-red-500/80 font-bold uppercase leading-tight">Aviso: A importação apagará os dados atuais deste dispositivo para aplicar o novo pacote.</p>
            </div>
          </div>

          <button 
            disabled={!inputCode}
            onClick={handleImport}
            className={`w-full py-4 rounded-xl font-black uppercase text-xs tracking-[0.2em] transition-all flex items-center justify-center gap-2 shadow-lg
              ${inputCode ? 'bg-emerald-600 hover:bg-emerald-500 text-white shadow-emerald-600/20' : 'bg-slate-800 text-slate-600 cursor-not-allowed'}
            `}
          >
            <Smartphone size={18} />
            Sincronizar Agora
          </button>
        </div>
      </div>

      {/* Zona de Perigo - Limpar Dados */}
      <div className="bg-red-500/5 border border-red-500/20 rounded-2xl p-8 space-y-6">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-red-500/10 rounded-lg text-red-500">
            <AlertTriangle size={20} />
          </div>
          <h3 className="text-lg font-black uppercase tracking-widest text-red-500">Zona de Perigo</h3>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <div className="bg-[#0f172a] p-6 rounded-xl border border-slate-800 space-y-4">
            <div>
              <h4 className="text-white font-bold text-sm uppercase">Limpar Histórico de Cargas</h4>
              <p className="text-[10px] text-slate-500 uppercase font-medium mt-1">Remove apenas as programações de cargas. Mantém unidades e equipes intactas.</p>
            </div>
            <button 
              onClick={onClearCargos}
              className="flex items-center gap-2 px-4 py-2 bg-slate-800 hover:bg-red-900/40 text-red-500 rounded-lg text-[10px] font-black uppercase transition-all border border-slate-700 hover:border-red-500/50"
            >
              <Trash2 size={14} /> Limpar Todas as Cargas
            </button>
          </div>

          <div className="bg-[#0f172a] p-6 rounded-xl border border-slate-800 space-y-4">
            <div>
              <h4 className="text-white font-bold text-sm uppercase">Redefinição de Fábrica</h4>
              <p className="text-[10px] text-slate-500 uppercase font-medium mt-1">Apaga permanentemente todos os dados (Unidades, Equipes e Cargas).</p>
            </div>
            <button 
              onClick={onClearAll}
              className="flex items-center gap-2 px-4 py-2 bg-red-600 hover:bg-red-500 text-white rounded-lg text-[10px] font-black uppercase transition-all shadow-lg shadow-red-600/20"
            >
              <RefreshCcw size={14} /> Redefinir Aplicação
            </button>
          </div>
        </div>
      </div>

      {/* Security Info */}
      <div className="flex items-center justify-center gap-8 py-6 border-t border-slate-800/50">
        <div className="flex items-center gap-2 text-[10px] font-black text-slate-600 uppercase tracking-widest">
          <ShieldCheck size={14} className="text-emerald-500" /> Criptografia Base64
        </div>
        <div className="flex items-center gap-2 text-[10px] font-black text-slate-600 uppercase tracking-widest">
          <CheckCircle2 size={14} className="text-emerald-500" /> Validação de Integridade
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { AirportBoard } from './components/AirportBoard';
import { TeamManager } from './components/TeamManager';
import { CargoManager } from './components/CargoManager';
import { UnitManager } from './components/UnitManager';
import { SyncView } from './components/SyncView';
import { Team, Cargo, ViewMode, CargoStatus, Unit } from './types';

const generateId = () => {
  try {
    return crypto.randomUUID();
  } catch (e) {
    return Math.random().toString(36).substring(2, 15) + Date.now().toString(36);
  }
};

const App: React.FC = () => {
  const [units, setUnits] = useState<Unit[]>(() => {
    const saved = localStorage.getItem('units_v2');
    return saved ? JSON.parse(saved) : [];
  });

  const [teams, setTeams] = useState<Team[]>(() => {
    const saved = localStorage.getItem('teams_v2');
    return saved ? JSON.parse(saved) : [];
  });

  const [cargos, setCargos] = useState<Cargo[]>(() => {
    const saved = localStorage.getItem('cargos_v2');
    return saved ? JSON.parse(saved) : [];
  });

  const [view, setView] = useState<ViewMode>('DASHBOARD');
  const [editingCargo, setEditingCargo] = useState<Cargo | null>(null);

  useEffect(() => {
    localStorage.setItem('units_v2', JSON.stringify(units));
  }, [units]);

  useEffect(() => {
    localStorage.setItem('teams_v2', JSON.stringify(teams));
  }, [teams]);

  useEffect(() => {
    localStorage.setItem('cargos_v2', JSON.stringify(cargos));
  }, [cargos]);

  // Gestão de Sincronização
  const handleImportSync = (data: { units: Unit[], teams: Team[], cargos: Cargo[] }) => {
    setUnits(data.units);
    setTeams(data.teams);
    setCargos(data.cargos);
    setView('DASHBOARD');
  };

  // Gestão Global
  const clearAllData = () => {
    if (window.confirm('ATENÇÃO: Isso irá apagar TUDO (Unidades, Equipes e Cargas) permanentemente. Deseja continuar?')) {
      setUnits([]);
      setCargos([]);
      setTeams([]);
      localStorage.removeItem('units_v2');
      localStorage.removeItem('teams_v2');
      localStorage.removeItem('cargos_v2');
      setView('DASHBOARD');
    }
  };

  const clearAllCargos = () => {
    if (window.confirm('Deseja apagar todas as cargas da lista? Unidades e Equipes serão mantidas.')) {
      setCargos([]);
      localStorage.removeItem('cargos_v2');
    }
  };

  // Gestão de Unidades
  const addUnit = (unit: Omit<Unit, 'id'>) => {
    setUnits(prev => [...prev, { ...unit, id: generateId() }]);
  };

  const updateUnit = (id: string, updated: Omit<Unit, 'id'>) => {
    setUnits(prev => prev.map(u => u.id === id ? { ...updated, id } : u));
    setTeams(prev => prev.map(t => t.unitId === id ? { ...t, unit: updated.name } : t));
    setCargos(prev => prev.map(c => c.unitId === id ? { ...c, unit: updated.name } : c));
  };

  const deleteUnit = (id: string) => {
    if (window.confirm('Excluir esta unidade? Isso não apagará equipes ou cargas, mas elas ficarão sem unidade vinculada.')) {
      setUnits(prev => prev.filter(u => u.id !== id));
      setTeams(prev => prev.map(t => t.unitId === id ? { ...t, unitId: '', unit: 'N/A' } : t));
      setCargos(prev => prev.map(c => c.unitId === id ? { ...c, unitId: '', unit: 'N/A' } : c));
    }
  };

  // Gestão de Equipes
  const addTeam = (teamData: Omit<Team, 'id'>) => {
    const unit = units.find(u => u.id === teamData.unitId);
    setTeams(prev => [...prev, { ...teamData, unit: unit?.name || 'N/A', id: generateId() }]);
  };

  const updateTeam = (id: string, updated: Omit<Team, 'id'>) => {
    const unit = units.find(u => u.id === updated.unitId);
    setTeams(prev => prev.map(t => t.id === id ? { ...updated, unit: unit?.name || 'N/A', id } : t));
  };

  const deleteTeam = (id: string) => {
    if (window.confirm('Excluir esta equipe e todas as suas cargas associadas?')) {
      setTeams(prev => prev.filter(t => t.id !== id));
      setCargos(prev => prev.filter(c => c.teamId !== id));
    }
  };

  // Gestão de Cargas
  const addCargo = (cargo: Omit<Cargo, 'id' | 'status'>) => {
    const unit = units.find(u => u.id === cargo.unitId);
    setCargos(prev => [...prev, { 
      ...cargo, 
      unit: unit?.name || 'N/A',
      id: generateId(), 
      status: CargoStatus.PROGRAMADO 
    }]);
    setView('DASHBOARD');
  };

  const bulkAddCargos = (newCargos: Omit<Cargo, 'id' | 'status'>[]) => {
    const formatted = newCargos.map(c => {
      const unit = units.find(u => u.id === c.unitId);
      return {
        ...c,
        unit: unit?.name || 'N/A',
        id: generateId(),
        status: CargoStatus.PROGRAMADO
      };
    });
    setCargos(prev => [...prev, ...formatted]);
    setView('DASHBOARD');
    alert(`${formatted.length} cargas importadas com sucesso!`);
  };

  const updateCargo = (id: string, updated: Partial<Cargo>) => {
    const unit = units.find(u => u.id === updated.unitId);
    setCargos(prev => prev.map(c => c.id === id ? { 
      ...c, 
      ...updated, 
      unit: unit ? unit.name : (updated.unit || c.unit) 
    } : c));
    setEditingCargo(null);
    setView('DASHBOARD');
  };

  const deleteCargo = (id: string) => {
    if (window.confirm('Deseja realmente excluir esta carga?')) {
      setCargos(prev => prev.filter(c => c.id !== id));
      if (editingCargo?.id === id) {
        setEditingCargo(null);
      }
    }
  };

  // Operações de Tempo
  const startCargo = (id: string) => {
    const now = new Date();
    const time = now.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
    updateCargo(id, { 
      status: CargoStatus.CARREGANDO, 
      startTime: time 
    });
  };

  const endCargo = (id: string) => {
    const now = new Date();
    const time = now.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
    const date = now.toLocaleDateString('pt-BR');
    updateCargo(id, { 
      status: CargoStatus.FINALIZADO, 
      endTime: time,
      endDate: date
    });
  };

  const handleEditCargo = (cargo: Cargo) => {
    setEditingCargo(cargo);
    setView('CARGO_ENTRY');
  };

  return (
    <Layout 
      view={view} 
      setView={setView} 
      onReset={clearAllData} 
      units={units}
    >
      {view === 'DASHBOARD' && (
        <AirportBoard 
          cargos={cargos} 
          teams={teams} 
          onStart={startCargo} 
          onEnd={endCargo}
          onDelete={deleteCargo}
          onEdit={handleEditCargo}
          onClearAll={clearAllCargos}
        />
      )}
      {view === 'UNITS' && (
        <UnitManager 
          units={units} 
          onAdd={addUnit} 
          onUpdate={updateUnit} 
          onDelete={deleteUnit} 
        />
      )}
      {view === 'TEAMS' && (
        <TeamManager 
          teams={teams} 
          units={units}
          onAdd={addTeam} 
          onUpdate={updateTeam} 
          onDelete={deleteTeam} 
        />
      )}
      {view === 'CARGO_ENTRY' && (
        <CargoManager 
          cargos={cargos} 
          teams={teams} 
          units={units}
          onAdd={addCargo} 
          onBulkAdd={bulkAddCargos}
          onUpdate={updateCargo} 
          onDelete={deleteCargo}
          onEdit={handleEditCargo}
          editingCargo={editingCargo}
          onCancel={() => { setEditingCargo(null); setView('DASHBOARD'); }}
        />
      )}
      {view === 'SYNC' && (
        <SyncView 
          units={units}
          teams={teams}
          cargos={cargos}
          onImport={handleImportSync}
          onClearCargos={clearAllCargos}
          onClearAll={clearAllData}
        />
      )}
    </Layout>
  );
};

