interface AirportBoardProps {
  cargos: Cargo[];
  teams: Team[];
  onStart: (id: string) => void;
  onEnd: (id: string) => void;
  onDelete: (id: string) => void;
  onEdit: (cargo: Cargo) => void;
  onClearAll: () => void;
}

export const AirportBoard: React.FC<AirportBoardProps> = ({ 
  cargos, 
  teams, 
  onStart, 
  onEnd, 
  onDelete, 
  onEdit,
  onClearAll
}) => {
  const [now, setNow] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 10000);
    return () => clearInterval(timer);
  }, []);

  const getTeamLabel = (teamId: string) => {
    const team = teams.find(t => t.id === teamId);
    return team ? `EQP ${team.number}` : '---';
  };

  const getEffectiveStatus = (cargo: Cargo): CargoStatus => {
    if (cargo.status === CargoStatus.PROGRAMADO) {
      const scheduledDate = new Date(cargo.pickupTime);
      if (now > scheduledDate) {
        return CargoStatus.ATRASADO;
      }
    }
    return cargo.status;
  };

  const formatDateTime = (isoString: string): { date: string; time: string; isPast: boolean } => {
    if (!isoString) return { date: '---', time: '---', isPast: false };
    try {
      const scheduledDate = new Date(isoString);
      if (isNaN(scheduledDate.getTime())) {
        return { date: '---', time: isoString || '---', isPast: false };
      }
      return {
        date: scheduledDate.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' }),
        time: scheduledDate.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
        isPast: now > scheduledDate
      };
    } catch {
      return { date: '---', time: isoString || '---', isPast: false };
    }
  };

  const getStatusStyle = (status: CargoStatus) => {
    switch (status) {
      case CargoStatus.PROGRAMADO: return 'text-sky-400 bg-sky-400/10 border-sky-400/20';
      case CargoStatus.CARREGANDO: return 'text-slate-900 bg-yellow-400 border-yellow-500 font-black shadow-[0_0_10px_rgba(234,179,8,0.5)]';
      case CargoStatus.FINALIZADO: return 'text-emerald-400 bg-emerald-400/10 border-emerald-400/20';
      case CargoStatus.ATRASADO: return 'text-red-500 bg-red-600 text-white border-red-400 font-black';
      default: return 'text-slate-400';
    }
  };

  // Ordenação por Nº Carga (Numérica)
  const sortedCargos = [...cargos].sort((a, b) => {
    return a.cargoNumber.localeCompare(b.cargoNumber, undefined, { numeric: true, sensitivity: 'base' });
  });

  const stats = cargos.reduce((acc, cargo) => {
    const status = getEffectiveStatus(cargo);
    const birds = cargo.birdCount || 0;

    if (status === CargoStatus.FINALIZADO) {
      acc.finalizado++;
      acc.avesFinalizado += birds;
    } else if (status === CargoStatus.CARREGANDO) {
      acc.carregando++;
      acc.avesCarregando += birds;
    } else if (status === CargoStatus.PROGRAMADO || status === CargoStatus.ATRASADO) {
      acc.programadoAtrasado++;
      acc.avesProgramadoAtrasado += birds;
      if (status === CargoStatus.ATRASADO) {
        acc.apenasAtrasado++;
      }
    }
    return acc;
  }, { 
    finalizado: 0, avesFinalizado: 0,
    carregando: 0, avesCarregando: 0,
    programadoAtrasado: 0, avesProgramadoAtrasado: 0,
    apenasAtrasado: 0 
  });

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black uppercase tracking-widest text-white airport-font">
            PAINEL DE <span className="text-yellow-500 underline decoration-yellow-500/30">LOGÍSTICA</span>
          </h2>
          <div className="flex items-center gap-4 mt-1">
            <p className="text-slate-500 text-xs font-bold uppercase tracking-tighter">Acompanhamento em tempo real</p>
            {cargos.length > 0 && (
              <button 
                onClick={onClearAll}
                className="flex items-center gap-1.5 text-[10px] font-black text-red-500 hover:text-red-400 transition-colors uppercase bg-red-500/10 px-2 py-1 rounded"
              >
                <ListX size={12} /> Limpar Todas as Cargas
              </button>
            )}
          </div>
        </div>

        <div className="flex flex-wrap gap-4 p-3 bg-slate-900/50 rounded-xl border border-slate-800">
          <div className="flex items-center gap-1.5 text-[10px] font-bold uppercase text-sky-400">
            <div className="w-2 h-2 rounded-full bg-sky-400"></div> PROGRAMADO
          </div>
          <div className="flex items-center gap-1.5 text-[10px] font-bold uppercase text-red-500">
            <div className="w-2 h-2 rounded-full bg-red-500 animate-ping"></div> ATRASADO
          </div>
          <div className="flex items-center gap-1.5 text-[10px] font-bold uppercase text-yellow-400">
            <div className="w-2 h-2 rounded-full bg-yellow-400 animate-pulse"></div> CARREGANDO
          </div>
          <div className="flex items-center gap-1.5 text-[10px] font-bold uppercase text-emerald-400">
            <div className="w-2 h-2 rounded-full bg-emerald-400"></div> FINALIZADO
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
        <div className="bg-[#0f172a] border border-emerald-500/30 rounded-2xl p-5 shadow-lg relative overflow-hidden group">
