            <div className="flex items-baseline gap-3">
              <span className="text-4xl font-black text-white airport-font">{stats.finalizado}</span>
              <span className="text-[10px] font-bold text-slate-500 uppercase">Viagens</span>
            </div>
            <div className="flex items-center gap-2 text-emerald-400 font-bold text-sm">
              <Bird size={14} />
              <span className="airport-font uppercase">{stats.avesFinalizado.toLocaleString()} Aves</span>
            </div>
          </div>
          <div className="mt-4 w-full bg-emerald-500/10 h-1.5 rounded-full overflow-hidden">
            <div className="bg-emerald-500 h-full transition-all duration-1000" style={{ width: cargos.length ? `${(stats.finalizado / cargos.length) * 100}%` : '0%' }} />
          </div>
        </div>

        <div className="bg-[#0f172a] border border-yellow-500/30 rounded-2xl p-5 shadow-lg relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
            <Zap size={64} className="text-yellow-500" />
          </div>
          <p className="text-[10px] font-black uppercase text-yellow-500/70 tracking-widest mb-1">Em Carregamento</p>
          <div className="flex flex-col gap-1">
            <div className="flex items-baseline gap-3">
              <span className="text-4xl font-black text-white airport-font">{stats.carregando}</span>
              <span className="text-[10px] font-bold text-slate-500 uppercase">Ativas</span>
            </div>
            <div className="flex items-center gap-2 text-yellow-500 font-bold text-sm">
              <Bird size={14} />
              <span className="airport-font uppercase">{stats.avesCarregando.toLocaleString()} Aves</span>
            </div>
          </div>
          <div className="mt-4 w-full bg-yellow-500/10 h-1.5 rounded-full overflow-hidden">
            <div className="bg-yellow-500 h-full animate-pulse" style={{ width: cargos.length ? `${(stats.carregando / cargos.length) * 100}%` : '0%' }} />
          </div>
        </div>

        <div className={`rounded-2xl p-5 shadow-lg relative overflow-hidden group border transition-all ${stats.apenasAtrasado > 0 ? 'bg-red-500/5 border-red-500/30' : 'bg-[#0f172a] border-sky-500/30'}`}>
          <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
            <Calendar size={64} className={stats.apenasAtrasado > 0 ? 'text-red-500' : 'text-sky-500'} />
          </div>
          <p className={`text-[10px] font-black uppercase tracking-widest mb-1 ${stats.apenasAtrasado > 0 ? 'text-red-500/70' : 'text-sky-500/70'}`}>Pendentes & Atrasadas</p>
          <div className="flex flex-col gap-1">
            <div className="flex items-baseline gap-3">
              <span className="text-4xl font-black text-white airport-font">{stats.programadoAtrasado}</span>
              <div className="flex flex-col">
                <span className="text-[10px] font-bold text-slate-500 uppercase leading-none">Total</span>
                {stats.apenasAtrasado > 0 && (
                  <span className="text-[10px] font-black text-red-500 uppercase mt-1 animate-pulse">
                     {stats.apenasAtrasado} Atrasadas
                  </span>
                )}
              </div>
            </div>
            <div className={`flex items-center gap-2 font-bold text-sm ${stats.apenasAtrasado > 0 ? 'text-red-500' : 'text-sky-400'}`}>
              <Bird size={14} />
              <span className="airport-font uppercase">{stats.avesProgramadoAtrasado.toLocaleString()} Aves</span>
            </div>
          </div>
          <div className="mt-4 w-full bg-slate-800 h-1.5 rounded-full overflow-hidden">
            <div className={`${stats.apenasAtrasado > 0 ? 'bg-red-500' : 'bg-sky-500'} h-full transition-all duration-1000`} style={{ width: cargos.length ? `${(stats.programadoAtrasado / cargos.length) * 100}%` : '0%' }} />
          </div>
        </div>
      </div>

      <div className="overflow-x-auto rounded-xl border border-slate-800 shadow-2xl bg-[#020617]">
        <table className="w-full text-left airport-font min-w-[1200px]">
          <thead>
            <tr className="bg-slate-900 text-slate-500 text-[11px] uppercase tracking-widest border-b border-slate-800">
              <th className="px-5 py-4">Status</th>
              <th className="px-5 py-4">Nº Carga</th>
              <th className="px-5 py-4">Equipe</th>
              <th className="px-5 py-4">Integrado</th>
              <th className="px-5 py-4">Cidade</th>
              <th className="px-5 py-4 text-center">Hora Apanha</th>
              <th className="px-5 py-4 text-center">Hora Abate</th>
              <th className="px-5 py-4 text-center">Aves</th>
              <th className="px-5 py-4 text-center">Peso (Kg)</th>
              <th className="px-5 py-4">Operação</th>
              <th className="px-5 py-4 text-center">Gestão</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800">
            {sortedCargos.length === 0 ? (
              <tr>
                <td colSpan={11} className="px-6 py-20 text-center text-slate-600">
                  <div className="flex flex-col items-center gap-2">
                    <AlertCircle size={40} className="opacity-20" />
                    <span className="uppercase font-bold tracking-widest">Nenhuma carga programada</span>
                  </div>
                </td>
              </tr>
            ) : (
              sortedCargos.map((cargo) => {
                const pickup = formatDateTime(cargo.pickupTime);
                const slaughter = formatDateTime(cargo.slaughterTime);
                const effectiveStatus = getEffectiveStatus(cargo);
                const isDelayed = effectiveStatus === CargoStatus.ATRASADO;
                const isLoading = effectiveStatus === CargoStatus.CARREGANDO;

                return (
                  <tr key={cargo.id} className={`hover:bg-slate-900/60 transition-colors ${isDelayed ? 'row-atrasado-blink' : ''} ${isLoading ? 'row-carregando-blink' : ''}`}>
                    <td className="px-5 py-5 whitespace-nowrap">
                      <span className={`px-2.5 py-1 rounded border text-[10px] tracking-widest shadow-sm ${getStatusStyle(effectiveStatus)}`}>
                        {effectiveStatus}
                      </span>
                    </td>
                    <td className="px-5 py-5">
                      <div className="flex items-center gap-2">
                        <Hash size={12} className="text-yellow-500/50" />
                        <span className="text-yellow-500 font-black text-lg">{cargo.cargoNumber}</span>
                      </div>
                    </td>
                    <td className="px-5 py-5">
                      <div className={`font-bold ${isDelayed || isLoading ? 'text-white' : 'text-white'}`}>{getTeamLabel(cargo.teamId)}</div>
                      <div className={`text-[10px] truncate max-w-[100px] uppercase font-bold ${isDelayed || isLoading ? 'text-white' : 'text-slate-500'}`}>{cargo.unit}</div>
                    </td>
                    <td className={`px-5 py-5 font-bold uppercase text-sm ${isDelayed || isLoading ? 'text-white' : 'text-slate-300'}`}>{cargo.integrated}</td>
                    <td className={`px-5 py-5 text-sm uppercase font-medium ${isDelayed || isLoading ? 'text-white' : 'text-slate-400'}`}>{cargo.city}</td>

                    <td className="px-5 py-5 text-center">
                      <div className={`font-black text-xl ${isDelayed || isLoading ? 'text-white drop-shadow-[0_0_8px_rgba(255,255,255,0.5)]' : 'text-sky-400'}`}>
                        {pickup.time}
                      </div>
                      <div className={`text-[10px] font-bold uppercase ${isDelayed || isLoading ? 'text-white' : 'text-slate-500'}`}>{pickup.date}</div>
                    </td>

                    <td className="px-5 py-5 text-center">
                      <div className={`font-black text-xl ${isDelayed || isLoading ? 'text-white' : 'text-yellow-500/80'}`}>
                        {slaughter.time}
                      </div>
                      <div className={`text-[10px] font-bold uppercase ${isDelayed || isLoading ? 'text-white' : 'text-slate-500'}`}>{slaughter.date}</div>
                    </td>

                    <td className={`px-5 py-5 text-center font-bold ${isDelayed || isLoading ? 'text-white' : 'text-slate-300'}`}>{cargo.birdCount.toLocaleString()}</td>
                    <td className={`px-5 py-5 text-center font-bold ${isDelayed || isLoading ? 'text-white' : 'text-slate-300'}`}>{cargo.totalLoad.toLocaleString()}</td>

                    <td className="px-5 py-5">
                      <div className="flex items-center gap-3">
                        {(cargo.status === CargoStatus.PROGRAMADO) && (
                          <button 
                            onClick={() => onStart(cargo.id)}
                            className={`flex items-center gap-1 px-3 py-1.5 rounded-md font-black text-[10px] uppercase transition-all shadow-lg ${
                              isDelayed 
                              ? 'bg-white text-red-600 hover:bg-slate-100 animate-bounce' 
                              : 'bg-sky-500 text-slate-900 hover:bg-sky-400'
                            }`}
                          >
                            <Play size={12} fill="currentColor" /> Início
                          </button>
                        )}
                        {cargo.status === CargoStatus.CARREGANDO && (
                          <button 
                            onClick={() => onEnd(cargo.id)}
                            className="flex items-center gap-1 px-3 py-1.5 bg-emerald-500 text-slate-900 rounded-md font-black text-[10px] uppercase hover:bg-emerald-400 transition-all shadow-lg animate-pulse"
                          >
                            <CheckCircle size={12} /> Fim
                          </button>
                        )}
                        {cargo.status === CargoStatus.FINALIZADO && (
                          <div className="flex flex-col text-[10px] leading-tight">
                            <span className="text-slate-500 font-bold">INÍCIO: <span className="text-white">{cargo.startTime}</span></span>
                            <span className="text-slate-500 font-bold">FIM: <span className="text-white">{cargo.endTime}</span></span>
                            <span className="text-emerald-500/80 font-bold mt-0.5">{cargo.endDate}</span>
                          </div>
                        )}
                      </div>
                    </td>

                    <td className="px-5 py-5">
                      <div className="flex justify-center gap-1">
                        <button 
                          onClick={() => onEdit(cargo)}
                          className={`p-2 rounded-lg transition-all ${isDelayed || isLoading ? 'text-white hover:bg-white/20' : 'text-slate-500 hover:text-yellow-500 hover:bg-yellow-500/10'}`}
                          title="Editar"
                        >
                          <Edit2 size={16} />
                        </button>
                        <button 
                          onClick={() => onDelete(cargo.id)}
                          className={`p-2 rounded-lg transition-all ${isDelayed || isLoading ? 'text-white hover:bg-white/20' : 'text-slate-500 hover:text-red-500 hover:bg-red-500/10'}`}
                          title="Excluir Permanentemente"
                        >
                          <Trash2 size={16} />
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Plus, Check, X, Truck, Trash2, Edit2, FileUp, Download } from 'lucide-react';
import { Cargo, Team, CargoStatus, Unit } from '../types';

interface CargoManagerProps {
  cargos: Cargo[];
  teams: Team[];
  units: Unit[];
  onAdd: (cargo: Omit<Cargo, 'id' | 'status'>) => void;
  onBulkAdd: (cargos: Omit<Cargo, 'id' | 'status'>[]) => void;
  onUpdate: (id: string, cargo: Partial<Cargo>) => void;
  onDelete: (id: string) => void;
  onEdit: (cargo: Cargo) => void;
  editingCargo: Cargo | null;
  onCancel: () => void;
}

export const CargoManager: React.FC<CargoManagerProps> = ({ 
  cargos, 
  teams, 
  units,
  onAdd, 
  onBulkAdd,
  onUpdate, 
  onDelete, 
  onEdit,
  editingCargo, 
  onCancel 
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [form, setForm] = useState<Omit<Cargo, 'id' | 'status'>>({
    cargoNumber: '',
    slaughterTime: '',
    teamId: '',
    integrated: '',
    city: '',
    pickupTime: '',
    birdCount: 0,
    totalLoad: 0,
    unitId: '',
    unit: ''
  });

  useEffect(() => {
    if (editingCargo) {
      setForm({
        cargoNumber: editingCargo.cargoNumber || '',
        slaughterTime: editingCargo.slaughterTime || '',
        teamId: editingCargo.teamId,
        integrated: editingCargo.integrated,
        city: editingCargo.city,
        pickupTime: editingCargo.pickupTime,
        birdCount: editingCargo.birdCount,
        totalLoad: editingCargo.totalLoad,
        unitId: editingCargo.unitId || '',
        unit: editingCargo.unit
      });
    } else {
      setForm({
        cargoNumber: '',
        slaughterTime: '',
        teamId: '',
        integrated: '',
        city: '',
        pickupTime: '',
        birdCount: 0,
        totalLoad: 0,
        unitId: '',
        unit: ''
      });
    }
  }, [editingCargo]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingCargo) {
      onUpdate(editingCargo.id, form);
    } else {
      onAdd(form);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      const lines = text.split('\n');
      const importedCargos: Omit<Cargo, 'id' | 'status'>[] = [];

      for (let i = 1; i < lines.length; i++) {
        const line = lines[i].trim();
        if (!line) continue;

        const values = line.includes(';') ? line.split(';') : line.split(',');

        // Espera agora pelo menos 9 campos no CSV se for atualizar o modelo de importação
        if (values.length >= 7) {
          const teamNumber = values[0].trim().replace(/[^0-9]/g, '');
          const team = teams.find(t => t.number === teamNumber);
          const unitName = (values[6] || '').trim().toUpperCase();
          const unit = units.find(u => u.name.toUpperCase() === unitName);

          if (team) {
            importedCargos.push({
              cargoNumber: (values[7] || '').trim() || (Math.floor(Math.random() * 9999)).toString(),
              slaughterTime: (values[8] || values[3] || '').trim(),
              teamId: team.id,
              integrated: values[1].trim(),
              city: values[2].trim(),
              pickupTime: values[3].trim(),
              birdCount: parseInt(values[4]) || 0,
              totalLoad: parseInt(values[5]) || 0,
              unitId: unit?.id || '',
              unit: unit?.name || (values[6] || '').trim()
            });
          }
        }
      }

      if (importedCargos.length > 0) {
        onBulkAdd(importedCargos);
      } else {
        alert("Nenhuma carga válida encontrada. Verifique se as equipes existem.");
      }

      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  const downloadTemplate = () => {
    const header = "Equipe,Integrado,Cidade,Hora Apanha,Numero Aves,Total Carga,Unidade,Numero Carga,Hora Abate\n";
    const example = "001,Produtor Exemplo,Cidade Exemplo,2024-05-20T08:00,5000,12000,UNIDADE A,10442,2024-05-20T14:00";
    const blob = new Blob([header + example], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'modelo_importacao_cargas.csv';
    a.click();
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      <div className="bg-[#1e293b] p-8 rounded-2xl border border-slate-700 shadow-2xl">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
          <h3 className="text-xl font-bold text-white flex items-center gap-3 uppercase tracking-widest">
            <Truck size={24} className="text-yellow-500" />
            {editingCargo ? 'Editar Carga' : 'Cadastro de Cargas'}
          </h3>

          <div className="flex gap-2">
            <button 
              onClick={downloadTemplate}
              className="flex items-center gap-2 px-3 py-2 rounded-lg text-[10px] font-black uppercase bg-slate-800 text-slate-400 hover:text-white transition-all border border-slate-700"
              title="Baixar Modelo CSV"
            >
              <Download size={14} /> Modelo
            </button>
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="flex items-center gap-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase bg-sky-600 text-white hover:bg-sky-500 transition-all shadow-lg shadow-sky-600/20"
            >
              <FileUp size={16} /> Importar Planilha
            </button>
            <input 
              type="file" 
              ref={fileInputRef} 
              onChange={handleFileUpload} 
              accept=".csv" 
              className="hidden" 
            />
          </div>
        </div>

        <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nº da Carga (ID Logístico)</label>
            <input 
              required
              type="text" 
              value={form.cargoNumber}
              onChange={e => setForm({...form, cargoNumber: e.target.value})}
              placeholder="Ex: 10442"
              className="w-full bg-[#0f172a] border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-yellow-500 outline-none transition-all airport-font font-bold text-yellow-500"
            />
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Equipe Responsável</label>
            <select 
              required
              value={form.teamId}
              onChange={e => setForm({...form, teamId: e.target.value})}
              className="w-full bg-[#0f172a] border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-yellow-500 outline-none transition-all appearance-none"
            >
              <option value="">Selecione a Equipe...</option>
              {teams.map(t => (
                <option key={t.id} value={t.id}>EQP {t.number} ({t.unit})</option>
              ))}
            </select>
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Integrado (Produtor)</label>
            <input 
              required
              type="text" 
              value={form.integrated}
              onChange={e => setForm({...form, integrated: e.target.value})}
              placeholder="Nome do integrado"
              className="w-full bg-[#0f172a] border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-yellow-500 outline-none transition-all"
            />
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Cidade</label>
            <input 
              required
              type="text" 
              value={form.city}
              onChange={e => setForm({...form, city: e.target.value})}
              placeholder="Cidade de origem/destino"
              className="w-full bg-[#0f172a] border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-yellow-500 outline-none transition-all"
            />
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Data e Hora Apanha</label>
            <input 
              required
              type="datetime-local" 
              value={form.pickupTime}
              onChange={e => setForm({...form, pickupTime: e.target.value})}
              className="w-full bg-[#0f172a] border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-yellow-500 outline-none transition-all font-bold airport-font"
            />
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Data e Hora Abate (Previsão)</label>
            <input 
              required
              type="datetime-local" 
              value={form.slaughterTime}
              onChange={e => setForm({...form, slaughterTime: e.target.value})}
              className="w-full bg-[#0f172a] border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-yellow-500 outline-none transition-all font-bold airport-font text-yellow-500/80"
            />
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Número de Aves</label>
            <input 
              required
              type="number" 
              value={form.birdCount || ''}
              onChange={e => setForm({...form, birdCount: parseInt(e.target.value) || 0})}
              placeholder="0"
              className="w-full bg-[#0f172a] border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-yellow-500 outline-none transition-all airport-font"
            />
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Total Carga (Kg)</label>
            <input 
              required
              type="number" 
              value={form.totalLoad || ''}
              onChange={e => setForm({...form, totalLoad: parseInt(e.target.value) || 0})}
              placeholder="0"
              className="w-full bg-[#0f172a] border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-yellow-500 outline-none transition-all airport-font"
            />
          </div>

          <div className="space-y-2 md:col-span-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Unidade</label>
            <select 
              required
              value={form.unitId}
              onChange={e => setForm({...form, unitId: e.target.value})}
              className="w-full bg-[#0f172a] border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-yellow-500 outline-none transition-all appearance-none"
            >
              <option value="">Selecione a Unidade...</option>
              {units.map(u => (
                <option key={u.id} value={u.id}>{u.name}</option>
              ))}
            </select>
          </div>

          <div className="md:col-span-2 flex justify-end gap-3 pt-6 border-t border-slate-700/50 mt-4">
            <button 
              type="button"
              onClick={onCancel}
              className="flex items-center gap-2 px-6 py-3 rounded-xl font-bold bg-slate-700 text-white hover:bg-slate-600 transition-all uppercase text-xs"
            >
              <X size={16} /> Cancelar
            </button>
            <button 
              type="submit"
              className="flex items-center gap-2 px-10 py-3 rounded-xl font-bold bg-yellow-500 text-slate-900 hover:bg-yellow-400 transition-all shadow-lg shadow-yellow-500/20 uppercase text-xs"
            >
              {editingCargo ? <Check size={18} /> : <Plus size={18} />}
              {editingCargo ? 'Salvar Alterações' : 'Cadastrar Carga'}
            </button>
          </div>
        </form>
      </div>

      <div className="bg-[#020617] rounded-2xl border border-slate-800 overflow-hidden shadow-2xl">
        <div className="overflow-x-auto">
          <table className="w-full text-left airport-font">
            <thead>
              <tr className="bg-slate-900/80 text-slate-500 text-[10px] uppercase tracking-widest border-b border-slate-800">
                <th className="px-6 py-4">Nº Carga / Equipe</th>
                <th className="px-6 py-4">Integrado</th>
                <th className="px-6 py-4 text-center">Aves/Kg</th>
                <th className="px-6 py-4 text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-800">
              {cargos.length === 0 ? (
                <tr>
                  <td colSpan={4} className="px-6 py-12 text-center text-slate-600 uppercase font-bold text-xs tracking-widest">Nenhuma carga cadastrada</td>
                </tr>
              ) : (
                [...cargos].sort((a,b) => a.cargoNumber.localeCompare(b.cargoNumber, undefined, {numeric: true})).map(cargo => {
                  const team = teams.find(t => t.id === cargo.teamId);
                  return (
                    <tr key={cargo.id} className="hover:bg-slate-900/40 transition-colors">
                      <td className="px-6 py-5">
