import React, { useState, useEffect, useRef } from 'react';
import { Plus, Check, X, Truck, Trash2, Edit2, FileUp, Download, Loader2 } from 'lucide-react';
import { Cargo, Team, CargoStatus, Unit } from '../types';

interface CargoManagerProps {
  cargos: Cargo[];
  teams: Team[];
  units: Unit[];
  onAdd: (cargo: Omit<Cargo, 'id' | 'status'>) => void;
  onBulkAdd: (cargos: Omit<Cargo, 'id' | 'status'>[]) => void;
  onUpdate: (id: string, cargo: Partial<Cargo>) => void;
  onDelete: (id: string) => void;
  onEdit: (cargo: Cargo) => void;
  editingCargo: Cargo | null;
  onCancel: () => void;
}

export const CargoManager: React.FC<CargoManagerProps> = ({ 
  cargos, 
  teams, 
  units,
  onAdd, 
  onBulkAdd,
  onUpdate, 
  onDelete, 
  onEdit,
  editingCargo, 
  onCancel 
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isImporting, setIsImporting] = useState(false);
  const [form, setForm] = useState<Omit<Cargo, 'id' | 'status'>>({
    cargoNumber: '',
    slaughterTime: '',
    teamId: '',
    integrated: '',
    city: '',
    pickupTime: '',
    birdCount: 0,
    totalLoad: 0,
    unitId: '',
    unit: ''
  });

  useEffect(() => {
    if (editingCargo) {
      setForm({
        cargoNumber: editingCargo.cargoNumber || '',
        slaughterTime: editingCargo.slaughterTime || '',
        teamId: editingCargo.teamId,
        integrated: editingCargo.integrated,
        city: editingCargo.city,
        pickupTime: editingCargo.pickupTime,
        birdCount: editingCargo.birdCount,
        totalLoad: editingCargo.totalLoad,
        unitId: editingCargo.unitId || '',
        unit: editingCargo.unit
      });
    } else {
      setForm({
        cargoNumber: '',
        slaughterTime: '',
        teamId: '',
        integrated: '',
        city: '',
        pickupTime: '',
        birdCount: 0,
        totalLoad: 0,
        unitId: '',
        unit: ''
      });
    }
  }, [editingCargo]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingCargo) {
      onUpdate(editingCargo.id, form);
    } else {
      onAdd(form);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsImporting(true);
    const reader = new FileReader();

    reader.onload = (event) => {
      try {
        const text = event.target?.result as string;
        const lines = text.split(/\r?\n/);
        const importedCargos: Omit<Cargo, 'id' | 'status'>[] = [];

        // Ignora o cabeçalho (i=1)
        for (let i = 1; i < lines.length; i++) {
          const line = lines[i].trim();
          if (!line) continue;

          // Suporta vírgula, ponto e vírgula ou tabulação
          const values = line.split(/[;,]/);

          if (values.length >= 6) {
            // Mapeamento esperado:
            // 0: Equipe (Número)
            // 1: Integrado
            // 2: Cidade
            // 3: Hora Apanha (YYYY-MM-DDTHH:mm)
            // 4: Numero Aves
            // 5: Total Carga (Kg)
            // 6: Unidade (Nome)
            // 7: Numero Carga
            // 8: Hora Abate (YYYY-MM-DDTHH:mm)

            const teamNum = values[0]?.trim() || '';
            const integrated = values[1]?.trim() || '';
            const city = values[2]?.trim() || '';
            const pickup = values[3]?.trim() || '';
            const birds = parseInt(values[4]) || 0;
            const load = parseInt(values[5]) || 0;
            const unitNameFromCSV = values[6]?.trim() || '';
            const cargoNum = values[7]?.trim() || (Math.floor(Math.random() * 90000) + 10000).toString();
            const slaughter = values[8]?.trim() || pickup;

            // Busca equipe pelo número
            const team = teams.find(t => t.number.trim() === teamNum.replace(/^EQP\s+/i, ''));
            // Busca unidade pelo nome (case insensitive)
            const unit = units.find(u => u.name.trim().toLowerCase() === unitNameFromCSV.toLowerCase());

            if (team) {
              importedCargos.push({
                cargoNumber: cargoNum,
                slaughterTime: slaughter,
                teamId: team.id,
                integrated: integrated,
                city: city,
                pickupTime: pickup,
                birdCount: birds,
                totalLoad: load,
                unitId: unit?.id || team.unitId || '',
                unit: unit?.name || team.unit || unitNameFromCSV
              });
            } else {
              console.warn(`Linha ${i}: Equipe "${teamNum}" não encontrada no sistema.`);
            }
          }
        }

        if (importedCargos.length > 0) {
          onBulkAdd(importedCargos);
        } else {
          alert("Nenhuma carga válida encontrada. Verifique se os números das equipes na planilha coincidem com as cadastradas.");
        }
      } catch (err) {
        console.error("Erro ao processar CSV:", err);
        alert("Erro ao processar arquivo. Verifique se o formato está correto.");
