import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { AirportBoard } from './components/AirportBoard';
import { TeamManager } from './components/TeamManager';
import { CargoManager } from './components/CargoManager';
import { UnitManager } from './components/UnitManager';
import { LoginScreen } from './components/LoginScreen';
import { Team, Cargo, ViewMode, CargoStatus, Unit } from './types';

const generateId = () => {
  try {
    return crypto.randomUUID();
  } catch (e) {
    return Math.random().toString(36).substring(2, 15) + Date.now().toString(36);
  }
};

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    return localStorage.getItem('cargo_auth_v2') === 'true';
  });

  const [units, setUnits] = useState<Unit[]>(() => {
    const saved = localStorage.getItem('units_v2');
    return saved ? JSON.parse(saved) : [];
  });

  const [teams, setTeams] = useState<Team[]>(() => {
    const saved = localStorage.getItem('teams_v2');
    return saved ? JSON.parse(saved) : [];
  });

  const [cargos, setCargos] = useState<Cargo[]>(() => {
    const saved = localStorage.getItem('cargos_v2');
    return saved ? JSON.parse(saved) : [];
  });

  const [view, setView] = useState<ViewMode>('DASHBOARD');
  const [editingCargo, setEditingCargo] = useState<Cargo | null>(null);

  useEffect(() => {
    localStorage.setItem('units_v2', JSON.stringify(units));
  }, [units]);

  useEffect(() => {
    localStorage.setItem('teams_v2', JSON.stringify(teams));
  }, [teams]);

  useEffect(() => {
    localStorage.setItem('cargos_v2', JSON.stringify(cargos));
  }, [cargos]);

  const handleLogin = () => {
    setIsAuthenticated(true);
    localStorage.setItem('cargo_auth_v2', 'true');
  };

  const handleLogout = () => {
    if (window.confirm('Deseja encerrar a sessão?')) {
      setIsAuthenticated(false);
      localStorage.removeItem('cargo_auth_v2');
    }
  };

  // Gestão Global
  const clearAllData = () => {
    if (window.confirm('ATENÇÃO: Isso irá apagar TUDO (Unidades, Equipes e Cargas) permanentemente. Deseja continuar?')) {
      setUnits([]);
      setCargos([]);
      setTeams([]);
      localStorage.removeItem('units_v2');
      localStorage.removeItem('teams_v2');
      localStorage.removeItem('cargos_v2');
      setView('DASHBOARD');
    }
  };

  const clearAllCargos = () => {
    if (window.confirm('Deseja apagar todas as cargas da lista? Unidades e Equipes serão mantidas.')) {
      setCargos([]);
      localStorage.removeItem('cargos_v2');
    }
  };

  // Gestão de Unidades
  const addUnit = (unit: Omit<Unit, 'id'>) => {
    setUnits(prev => [...prev, { ...unit, id: generateId() }]);
  };

  const updateUnit = (id: string, updated: Omit<Unit, 'id'>) => {
    setUnits(prev => prev.map(u => u.id === id ? { ...updated, id } : u));
    setTeams(prev => prev.map(t => t.unitId === id ? { ...t, unit: updated.name } : t));
    setCargos(prev => prev.map(c => c.unitId === id ? { ...c, unit: updated.name } : c));
  };

  const deleteUnit = (id: string) => {
    if (window.confirm('Excluir esta unidade? Isso não apagará equipes ou cargas, mas elas ficarão sem unidade vinculada.')) {
      setUnits(prev => prev.filter(u => u.id !== id));
      setTeams(prev => prev.map(t => t.unitId === id ? { ...t, unitId: '', unit: 'N/A' } : t));
      setCargos(prev => prev.map(c => c.unitId === id ? { ...c, unitId: '', unit: 'N/A' } : c));
    }
  };

  // Gestão de Equipes
  const addTeam = (teamData: Omit<Team, 'id'>) => {
    const unit = units.find(u => u.id === teamData.unitId);
    setTeams(prev => [...prev, { ...teamData, unit: unit?.name || 'N/A', id: generateId() }]);
  };

  const updateTeam = (id: string, updated: Omit<Team, 'id'>) => {
    const unit = units.find(u => u.id === updated.unitId);
    setTeams(prev => prev.map(t => t.id === id ? { ...updated, unit: unit?.name || 'N/A', id } : t));
  };

  const deleteTeam = (id: string) => {
    if (window.confirm('Excluir esta equipe e todas as suas cargas associadas?')) {
      setTeams(prev => prev.filter(t => t.id !== id));
      setCargos(prev => prev.filter(c => c.teamId !== id));
    }
  };

  // Gestão de Cargas
  const addCargo = (cargo: Omit<Cargo, 'id' | 'status'>) => {
    const unit = units.find(u => u.id === cargo.unitId);
    setCargos(prev => [...prev, { 
      ...cargo, 
      unit: unit?.name || 'N/A',
      id: generateId(), 
      status: CargoStatus.PROGRAMADO 
    }]);
    setView('DASHBOARD');
  };

  const bulkAddCargos = (newCargos: Omit<Cargo, 'id' | 'status'>[]) => {
    const formatted = newCargos.map(c => {
      const unit = units.find(u => u.id === c.unitId);
      return {
        ...c,
        unit: unit?.name || 'N/A',
        id: generateId(),
        status: CargoStatus.PROGRAMADO
      };
    });
    setCargos(prev => [...prev, ...formatted]);
    setView('DASHBOARD');
    alert(`${formatted.length} cargas importadas com sucesso!`);
  };

  const updateCargo = (id: string, updated: Partial<Cargo>) => {
    const unit = units.find(u => u.id === updated.unitId);
    setCargos(prev => prev.map(c => c.id === id ? { 
      ...c, 
      ...updated, 
      unit: unit ? unit.name : (updated.unit || c.unit) 
    } : c));
    setEditingCargo(null);
    setView('DASHBOARD');
  };

  const deleteCargo = (id: string) => {
    if (window.confirm('Deseja realmente excluir esta carga?')) {
      setCargos(prev => prev.filter(c => c.id !== id));
      if (editingCargo?.id === id) {
        setEditingCargo(null);
      }
    }
  };

  // Operações de Tempo
  const startCargo = (id: string) => {
    const now = new Date();
    const time = now.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
    updateCargo(id, { 
      status: CargoStatus.CARREGANDO, 
      startTime: time 
    });
  };

  const endCargo = (id: string) => {
    const now = new Date();
    const time = now.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
    const date = now.toLocaleDateString('pt-BR');
    updateCargo(id, { 
      status: CargoStatus.FINALIZADO, 
      endTime: time,
      endDate: date
    });
  };

  const handleEditCargo = (cargo: Cargo) => {
    setEditingCargo(cargo);
    setView('CARGO_ENTRY');
  };

  if (!isAuthenticated) {
    return <LoginScreen onLogin={handleLogin} />;
  }

  return (
    <Layout 
      view={view} 
      setView={setView} 
      onReset={clearAllData} 
      units={units}
    >
      {view === 'DASHBOARD' && (
        <AirportBoard 
          cargos={cargos} 
          teams={teams} 
          onStart={startCargo} 
          onEnd={endCargo}
          onDelete={deleteCargo}
          onEdit={handleEditCargo}
          onClearAll={clearAllCargos}
        />
      )}
      {view === 'UNITS' && (
        <UnitManager 
          units={units} 
          onAdd={addUnit} 
          onUpdate={updateUnit} 
          onDelete={deleteUnit} 
        />
      )}
      {view === 'TEAMS' && (
        <TeamManager 
          teams={teams} 
          units={units}
          onAdd={addTeam} 
          onUpdate={updateTeam} 
          onDelete={deleteTeam} 
        />
      )}
      {view === 'CARGO_ENTRY' && (
        <CargoManager 
          cargos={cargos} 
          teams={teams} 
          units={units}
          onAdd={addCargo} 
          onBulkAdd={bulkAddCargos}
          onUpdate={updateCargo} 
          onDelete={deleteCargo}
          onEdit={handleEditCargo}
          editingCargo={editingCargo}
          onCancel={() => { setEditingCargo(null); setView('DASHBOARD'); }}
        />
      )}

      {/* Botão Flutuante de Logout (Discreto) */}
      <button 
        onClick={handleLogout}
        className="fixed bottom-6 right-6 p-3 bg-slate-900/50 hover:bg-red-500/10 text-slate-500 hover:text-red-500 rounded-full border border-slate-800 transition-all z-50 group shadow-2xl backdrop-blur-md"
        title="Sair do Sistema"
      >
        <Lock size={16} className="group-hover:hidden" />
        <span className="hidden group-hover:block text-[10px] font-black uppercase px-2">Encerrar Sessão</span>
      </button>
    </Layout>
  );
};

