const generateId = () => {
  try {
    return crypto.randomUUID();
  } catch (e) {
    return Math.random().toString(36).substring(2, 15) + Date.now().toString(36);
  }
};

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    return localStorage.getItem('cargo_auth_v2') === 'true';
  });

  const [isBooting, setIsBooting] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [units, setUnits] = useState<Unit[]>([]);
  const [teams, setTeams] = useState<Team[]>([]);
  const [cargos, setCargos] = useState<Cargo[]>([]);
  const [view, setView] = useState<ViewMode>('DASHBOARD');
  const [editingCargo, setEditingCargo] = useState<Cargo | null>(null);

  // Carregamento inicial (Fetch from Supabase or LocalStorage)
  useEffect(() => {
    const loadInitialData = async () => {
      setIsSyncing(true);

      // Tentativa de carregar do LocalStorage primeiro para rapidez
      const savedUnits = localStorage.getItem('units_v2');
      const savedTeams = localStorage.getItem('teams_v2');
      const savedCargos = localStorage.getItem('cargos_v2');

      if (savedUnits) setUnits(JSON.parse(savedUnits));
      if (savedTeams) setTeams(JSON.parse(savedTeams));
      if (savedCargos) setCargos(JSON.parse(savedCargos));

      /** 
       * Lógica de Sincronização Supabase (Comentada até que as chaves sejam válidas)
       * 
       * const { data: dbUnits } = await supabase.from('units').select('*');
       * if (dbUnits) setUnits(dbUnits);
       * ... similar para teams e cargos
       */

      setIsSyncing(false);
    };

    if (isAuthenticated) {
      loadInitialData();
    }
  }, [isAuthenticated]);

  // Persistência em cache local para redundância
  useEffect(() => {
    if (units.length) localStorage.setItem('units_v2', JSON.stringify(units));
  }, [units]);

  useEffect(() => {
    if (teams.length) localStorage.setItem('teams_v2', JSON.stringify(teams));
  }, [teams]);

  useEffect(() => {
    if (cargos.length) localStorage.setItem('cargos_v2', JSON.stringify(cargos));
  }, [cargos]);

  const handleLogin = () => {
    setIsBooting(true);
    setTimeout(() => {
      setIsAuthenticated(true);
      setIsBooting(false);
      localStorage.setItem('cargo_auth_v2', 'true');
    }, 2500);
  };

  const handleLogout = () => {
    if (window.confirm('Deseja encerrar a sessão?')) {
      setIsAuthenticated(false);
      localStorage.removeItem('cargo_auth_v2');
    }
  };

  // HANDLERS ASSÍNCRONOS (Prepared for Supabase)

  const addUnit = async (unitData: Omit<Unit, 'id'>) => {
    setIsSyncing(true);
    const newUnit = { ...unitData, id: generateId() };

    // DB Push: await supabase.from('units').insert([newUnit]);

    setUnits(prev => [...prev, newUnit]);
    setIsSyncing(false);
  };

  const updateUnit = async (id: string, updated: Omit<Unit, 'id'>) => {
    setIsSyncing(true);
    // DB Push: await supabase.from('units').update(updated).eq('id', id);

    setUnits(prev => prev.map(u => u.id === id ? { ...updated, id } : u));
    setTeams(prev => prev.map(t => t.unitId === id ? { ...t, unit: updated.name } : t));
    setCargos(prev => prev.map(c => c.unitId === id ? { ...c, unit: updated.name } : c));
    setIsSyncing(false);
  };

  const deleteUnit = async (id: string) => {
    if (window.confirm('Excluir esta unidade?')) {
      setIsSyncing(true);
      // DB Push: await supabase.from('units').delete().eq('id', id);

      setUnits(prev => prev.filter(u => u.id !== id));
      setTeams(prev => prev.map(t => t.unitId === id ? { ...t, unitId: '', unit: 'N/A' } : t));
      setCargos(prev => prev.map(c => c.unitId === id ? { ...c, unitId: '', unit: 'N/A' } : c));
      setIsSyncing(false);
    }
  };

  const addTeam = async (teamData: Omit<Team, 'id'>) => {
    setIsSyncing(true);
    const unit = units.find(u => u.id === teamData.unitId);
    const newTeam = { ...teamData, unit: unit?.name || 'N/A', id: generateId() };

    // DB Push: await supabase.from('teams').insert([newTeam]);

    setTeams(prev => [...prev, newTeam]);
    setIsSyncing(false);
  };

  const updateTeam = async (id: string, updated: Omit<Team, 'id'>) => {
    setIsSyncing(true);
    const unit = units.find(u => u.id === updated.unitId);
    // DB Push: await supabase.from('teams').update({ ...updated, unit: unit?.name }).eq('id', id);

    setTeams(prev => prev.map(t => t.id === id ? { ...updated, unit: unit?.name || 'N/A', id } : t));
    setIsSyncing(false);
  };

  const deleteTeam = async (id: string) => {
    if (window.confirm('Excluir esta equipe?')) {
      setIsSyncing(true);
      // DB Push: await supabase.from('teams').delete().eq('id', id);

      setTeams(prev => prev.filter(t => t.id !== id));
      setCargos(prev => prev.filter(c => c.teamId !== id));
      setIsSyncing(false);
    }
  };

  const addCargo = async (cargo: Omit<Cargo, 'id' | 'status'>) => {
    setIsSyncing(true);
    const unit = units.find(u => u.id === cargo.unitId);
    const newCargo: Cargo = { 
      ...cargo, 
      unit: unit?.name || 'N/A',
      id: generateId(), 
      status: CargoStatus.PROGRAMADO 
    };

    // DB Push: await supabase.from('cargos').insert([newCargo]);

    setCargos(prev => [...prev, newCargo]);
    setView('DASHBOARD');
    setIsSyncing(false);
  };

  const updateCargo = async (id: string, updated: Partial<Cargo>) => {
    setIsSyncing(true);
    const unit = units.find(u => u.id === updated.unitId);
    const cargoToUpdate = cargos.find(c => c.id === id);

    if (!cargoToUpdate) return;

    const merged = { 
      ...cargoToUpdate, 
      ...updated, 
      unit: unit ? unit.name : (updated.unit || cargoToUpdate.unit) 
    };

    // DB Push: await supabase.from('cargos').update(merged).eq('id', id);

    setCargos(prev => prev.map(c => c.id === id ? merged : c));
    setEditingCargo(null);
    setView('DASHBOARD');
    setIsSyncing(false);
  };

  const deleteCargo = async (id: string) => {
    if (window.confirm('Deseja realmente excluir esta carga?')) {
      setIsSyncing(true);
      // DB Push: await supabase.from('cargos').delete().eq('id', id);

      setCargos(prev => prev.filter(c => c.id !== id));
      if (editingCargo?.id === id) setEditingCargo(null);
      setIsSyncing(false);
    }
  };

  const startCargo = (id: string) => {
    const now = new Date();
    const time = now.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
    updateCargo(id, { status: CargoStatus.CARREGANDO, startTime: time });
  };

  const endCargo = (id: string) => {
    const now = new Date();
    const time = now.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
    const date = now.toLocaleDateString('pt-BR');
    updateCargo(id, { status: CargoStatus.FINALIZADO, endTime: time, endDate: date });
  };

  const handleEditCargo = (cargo: Cargo) => {
    setEditingCargo(cargo);
    setView('CARGO_ENTRY');
  };

  if (isBooting) {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center space-y-8">
        <div className="relative">
          <Cpu size={80} className="text-yellow-500 animate-pulse" />
          <div className="absolute inset-0 bg-yellow-500/20 blur-3xl animate-pulse" />
        </div>
        <div className="text-center space-y-2">
          <h2 className="text-2xl font-black text-white airport-font uppercase tracking-[0.3em]">
            Acessando <span className="text-yellow-500">Torre de Controle</span>
          </h2>
          <div className="flex items-center justify-center gap-2 text-slate-500 text-[10px] font-black uppercase tracking-widest">
            <Loader2 size={12} className="animate-spin text-yellow-500" />
            Sincronizando CargoFlightBoard...
          </div>
        </div>
        <div className="w-64 h-1 bg-slate-900 rounded-full overflow-hidden">
          <div className="h-full bg-yellow-500 animate-progress" style={{ width: '100%' }} />
        </div>
      </div>
    );
  }

  if (!isAuthenticated) {
    return <LoginScreen onLogin={handleLogin} />;
  }

  return (
    <Layout view={view} setView={setView} onReset={() => {}} units={units}>
      {/* Indicador de Sincronização em Tempo Real */}
      <div className={`fixed top-4 right-8 z-[60] flex items-center gap-2 px-3 py-1.5 rounded-full bg-slate-900/80 border border-slate-800 backdrop-blur-md transition-all duration-500 ${isSyncing ? 'opacity-100 translate-y-0' : 'opacity-0 -translate-y-4 pointer-events-none'}`}>
        <Database size={12} className="text-yellow-500 animate-bounce" />
        <span className="text-[9px] font-black text-white uppercase tracking-widest">Sincronizando Banco</span>
      </div>

      {view === 'DASHBOARD' && (
        <AirportBoard 
          cargos={cargos} teams={teams} onStart={startCargo} onEnd={endCargo}
          onDelete={deleteCargo} onEdit={handleEditCargo} onClearAll={() => setCargos([])}
        />
      )}
      {view === 'UNITS' && <UnitManager units={units} onAdd={addUnit} onUpdate={updateUnit} onDelete={deleteUnit} />}
      {view === 'TEAMS' && <TeamManager teams={teams} units={units} onAdd={addTeam} onUpdate={updateTeam} onDelete={deleteTeam} />}
      {view === 'CARGO_ENTRY' && (
        <CargoManager 
          cargos={cargos} teams={teams} units={units} onAdd={addCargo} onBulkAdd={(list) => list.forEach(addCargo)}
          onUpdate={updateCargo} onDelete={deleteCargo} onEdit={handleEditCargo}
          editingCargo={editingCargo} onCancel={() => { setEditingCargo(null); setView('DASHBOARD'); }}
        />
      )}

      <button 
        onClick={handleLogout}
        className="fixed bottom-6 right-6 p-3 bg-slate-900/80 hover:bg-red-500/10 text-slate-500 hover:text-red-500 rounded-full border border-slate-800 transition-all z-50 group shadow-2xl backdrop-blur-md"
      >
        <ShieldCheck size={16} />
      </button>
    </Layout>
  );
};

export default App;

