          </h2>
          <div className="flex items-center justify-center gap-2 text-slate-500 text-[10px] font-black uppercase tracking-widest">
            <Loader2 size={12} className="animate-spin text-yellow-500" />
            Sincronizando CargoFlightBoard...
          </div>
        </div>
        <div className="w-64 h-1 bg-slate-900 rounded-full overflow-hidden">
          <div className="h-full bg-yellow-500 animate-progress" style={{ width: '100%' }} />
        </div>
      </div>
    );
  }

  if (!isAuthenticated) {
    return <LoginScreen onLogin={handleLogin} />;
  }

  return (
    <Layout view={view} setView={setView} onReset={() => {}} units={units}>
      <div className={`fixed top-4 right-8 z-[60] flex items-center gap-2 px-3 py-1.5 rounded-full bg-slate-900/80 border border-slate-800 backdrop-blur-md transition-all duration-500 ${isSyncing ? 'opacity-100 translate-y-0' : 'opacity-0 -translate-y-4 pointer-events-none'}`}>
        <Database size={12} className="text-yellow-500 animate-bounce" />
        <span className="text-[9px] font-black text-white uppercase tracking-widest">Sincronizando Banco</span>
      </div>

      {view === 'DASHBOARD' && (
        <AirportBoard 
          cargos={cargos} teams={teams} units={units} onStart={startCargo} onEnd={endCargo}
          onDelete={deleteCargo} onEdit={handleEditCargo} onClearAll={() => setCargos([])}
        />
      )}
      {view === 'UNITS' && <UnitManager units={units} onAdd={addUnit} onUpdate={updateUnit} onDelete={deleteUnit} />}
      {view === 'TEAMS' && <TeamManager teams={teams} units={units} onAdd={addTeam} onUpdate={updateTeam} onDelete={deleteTeam} />}
      {view === 'CARGO_ENTRY' && (
        <CargoManager 
          cargos={cargos} teams={teams} units={units} onAdd={addCargo} onBulkAdd={(list) => list.forEach(addCargo)}
          onUpdate={updateCargo} onDelete={deleteCargo} onEdit={handleEditCargo}
          editingCargo={editingCargo} onCancel={() => { setEditingCargo(null); setView('DASHBOARD'); }}
        />
      )}

      <button 
        onClick={handleLogout}
        className="fixed bottom-6 right-6 p-3 bg-slate-900/80 hover:bg-red-500/10 text-slate-500 hover:text-red-500 rounded-full border border-slate-800 transition-all z-50 group shadow-2xl backdrop-blur-md"
      >
        <ShieldCheck size={16} />
      </button>
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Play, 
  CheckCircle, 
  Trash2, 
  Edit2, 
  AlertCircle, 
  ListX, 
  Clock, 
  Calendar, 
  Zap, 
  Bird, 
  Hash, 
  Radio, 
  Filter, 
  XCircle,
  Building2,
  Users as UsersIcon
} from 'lucide-react';
import { Cargo, Team, CargoStatus, Unit } from '../types';

interface AirportBoardProps {
  cargos: Cargo[];
  teams: Team[];
  units: Unit[];
  onStart: (id: string) => void;
  onEnd: (id: string) => void;
  onDelete: (id: string) => void;
  onEdit: (cargo: Cargo) => void;
  onClearAll: () => void;
}

export const AirportBoard: React.FC<AirportBoardProps> = ({ 
  cargos, 
  teams, 
  units,
  onStart, 
  onEnd, 
  onDelete, 
  onEdit,
  onClearAll
}) => {
  const [now, setNow] = useState(new Date());

  // Filtros
  const [filterUnitId, setFilterUnitId] = useState('');
  const [filterTeamId, setFilterTeamId] = useState('');
  const [filterSlaughterDate, setFilterSlaughterDate] = useState('');

  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 10000);
    return () => clearInterval(timer);
  }, []);

  const getTeamLabel = (teamId: string) => {
    const team = teams.find(t => t.id === teamId);
    return team ? `EQP ${team.number}` : '---';
  };

  const getEffectiveStatus = (cargo: Cargo): CargoStatus => {
    if (cargo.status === CargoStatus.PROGRAMADO) {
      const scheduledDate = new Date(cargo.pickupTime);
      if (now > scheduledDate) return CargoStatus.ATRASADO;
    }
    return cargo.status;
  };

  const formatDateTime = (isoString: string): { date: string; time: string; isPast: boolean } => {
    if (!isoString) return { date: '---', time: '---', isPast: false };
    try {
      const scheduledDate = new Date(isoString);
      if (isNaN(scheduledDate.getTime())) return { date: '---', time: isoString || '---', isPast: false };
      return {
        date: scheduledDate.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' }),
        time: scheduledDate.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
        isPast: now > scheduledDate
      };
    } catch {
      return { date: '---', time: isoString || '---', isPast: false };
    }
  };

  const getStatusStyle = (status: CargoStatus) => {
    switch (status) {
      case CargoStatus.PROGRAMADO: return 'text-sky-400 bg-sky-400/5 border-sky-400/30';
      case CargoStatus.CARREGANDO: return 'text-slate-950 bg-yellow-500 border-yellow-500 font-black shadow-[0_0_15px_rgba(234,179,8,0.4)]';
      case CargoStatus.FINALIZADO: return 'text-emerald-400 bg-emerald-400/5 border-emerald-400/30';
      case CargoStatus.ATRASADO: return 'text-white bg-red-600 border-red-500 font-black animate-pulse';
      default: return 'text-slate-400';
    }
  };

  // Lógica de Filtragem e Ordenação
  const filteredAndSortedCargos = useMemo(() => {
    return cargos
      .filter(cargo => {
        const matchesUnit = !filterUnitId || cargo.unitId === filterUnitId;
        const matchesTeam = !filterTeamId || cargo.teamId === filterTeamId;

        let matchesDate = true;
        if (filterSlaughterDate) {
          const cargoDate = cargo.slaughterTime.split('T')[0];
          matchesDate = cargoDate === filterSlaughterDate;
        }

        return matchesUnit && matchesTeam && matchesDate;
      })
      .sort((a, b) => {
        return a.cargoNumber.localeCompare(b.cargoNumber, undefined, { numeric: true, sensitivity: 'base' });
      });
  }, [cargos, filterUnitId, filterTeamId, filterSlaughterDate]);

  const stats = filteredAndSortedCargos.reduce((acc, cargo) => {
    const status = getEffectiveStatus(cargo);
    const birds = cargo.birdCount || 0;
    if (status === CargoStatus.FINALIZADO) { acc.finalizado++; acc.avesFinalizado += birds; }
    else if (status === CargoStatus.CARREGANDO) { acc.carregando++; acc.avesCarregando += birds; }
    else { acc.programadoAtrasado++; acc.avesProgramadoAtrasado += birds; if (status === CargoStatus.ATRASADO) acc.apenasAtrasado++; }
    return acc;
  }, { finalizado: 0, avesFinalizado: 0, carregando: 0, avesCarregando: 0, programadoAtrasado: 0, avesProgramadoAtrasado: 0, apenasAtrasado: 0 });

  const clearFilters = () => {
    setFilterUnitId('');
    setFilterTeamId('');
    setFilterSlaughterDate('');
  };

  return (
    <div className="space-y-10">
      {/* Header Estilo Terminal de Aeroporto */}
      <div className="flex flex-col lg:flex-row lg:items-end justify-between gap-8 pb-8 border-b border-slate-800">
        <div className="space-y-4">
          <div className="flex items-center gap-3">
            <span className="px-3 py-1 bg-yellow-500 text-slate-950 text-[10px] font-black uppercase tracking-widest rounded">AO VIVO</span>
            <div className="h-px w-20 bg-slate-800" />
            <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Sincronizado com Torre</span>
          </div>
          <h2 className="text-5xl font-black uppercase tracking-tighter text-white airport-font">
            CargoFlight<span className="text-yellow-500">Board</span>
          </h2>
          <div className="flex items-center gap-6">
            <p className="text-slate-500 text-xs font-bold uppercase tracking-[0.2em]">Fluxo Operacional de Logística</p>
            {cargos.length > 0 && (
              <button 
                onClick={onClearAll}
                className="flex items-center gap-2 text-[10px] font-black text-red-500 hover:text-white transition-all uppercase bg-red-500/5 hover:bg-red-600 px-4 py-2 rounded-xl border border-red-500/20"
              >
                <ListX size={14} /> Limpar Painel
              </button>
            )}
          </div>
        </div>

        <div className="flex flex-wrap gap-4 p-5 bg-slate-900/40 rounded-3xl border border-slate-800 backdrop-blur-md">
          <div className="flex items-center gap-3 text-[10px] font-black uppercase text-sky-400">
            <div className="w-2.5 h-2.5 rounded-full bg-sky-400 shadow-[0_0_8px_rgba(56,189,248,0.5)]" /> PROGRAMADO
          </div>
          <div className="flex items-center gap-3 text-[10px] font-black uppercase text-red-500">
            <div className="w-2.5 h-2.5 rounded-full bg-red-500 animate-ping" /> ATRASADO
          </div>
          <div className="flex items-center gap-3 text-[10px] font-black uppercase text-yellow-400">
            <div className="w-2.5 h-2.5 rounded-full bg-yellow-400 animate-pulse" /> CARREGANDO
          </div>
          <div className="flex items-center gap-3 text-[10px] font-black uppercase text-emerald-400">
            <div className="w-2.5 h-2.5 rounded-full bg-emerald-400" /> FINALIZADO
          </div>
        </div>
      </div>

      {/* Painel de Filtros (Novo) */}
      <div className="bg-[#0f172a]/40 backdrop-blur-xl border border-slate-800 rounded-[2rem] p-6 shadow-xl border-t-white/5">
        <div className="flex flex-col md:flex-row items-center gap-6">
          <div className="flex items-center gap-3 text-yellow-500 shrink-0">
            <Filter size={18} />
            <span className="text-[10px] font-black uppercase tracking-[0.3em]">Filtros Operacionais</span>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 flex-1 w-full">
            {/* Filtro por Unidade */}
            <div className="relative group">
              <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-slate-500 group-hover:text-yellow-500 transition-colors">
                <Building2 size={14} />
              </div>
              <select 
                value={filterUnitId}
                onChange={(e) => setFilterUnitId(e.target.value)}
                className="w-full bg-black/40 border border-slate-800 text-white rounded-xl py-3 pl-10 pr-4 outline-none focus:border-yellow-500/50 transition-all text-[11px] font-black uppercase appearance-none cursor-pointer"
              >
                <option value="">Todas as Unidades</option>
                {units.map(u => (
                  <option key={u.id} value={u.id}>{u.name}</option>
                ))}
              </select>
            </div>

            {/* Filtro por Equipe */}
            <div className="relative group">
              <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-slate-500 group-hover:text-yellow-500 transition-colors">
                <UsersIcon size={14} />
              </div>
              <select 
                value={filterTeamId}
                onChange={(e) => setFilterTeamId(e.target.value)}
                className="w-full bg-black/40 border border-slate-800 text-white rounded-xl py-3 pl-10 pr-4 outline-none focus:border-yellow-500/50 transition-all text-[11px] font-black uppercase appearance-none cursor-pointer"
              >
                <option value="">Todas as Equipes</option>
                {teams.map(t => (
                  <option key={t.id} value={t.id}>EQP {t.number}</option>
                ))}
              </select>
            </div>

            {/* Filtro por Data Abate */}
            <div className="relative group">
              <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-slate-500 group-hover:text-yellow-500 transition-colors">
                <Calendar size={14} />
              </div>
              <input 
                type="date"
                value={filterSlaughterDate}
                onChange={(e) => setFilterSlaughterDate(e.target.value)}
                className="w-full bg-black/40 border border-slate-800 text-white rounded-xl py-3 pl-10 pr-4 outline-none focus:border-yellow-500/50 transition-all text-[11px] font-black uppercase cursor-pointer"
              />
            </div>
          </div>

          {(filterUnitId || filterTeamId || filterSlaughterDate) && (
            <button 
              onClick={clearFilters}
              className="flex items-center gap-2 px-6 py-3 rounded-xl bg-slate-800 hover:bg-slate-700 text-white text-[10px] font-black uppercase tracking-widest transition-all"
            >
              <XCircle size={14} /> Limpar Filtros
            </button>
          )}
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
        <div className="bg-[#0f172a]/40 border border-emerald-500/20 rounded-[2.5rem] p-8 shadow-2xl relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-8 opacity-10 group-hover:scale-125 transition-transform group-hover:rotate-12">
            <CheckCircle size={80} className="text-emerald-500" />
          </div>
          <p className="text-[10px] font-black uppercase text-emerald-500 tracking-[0.3em] mb-2">Completados</p>
          <div className="flex items-baseline gap-4 mb-4">
            <span className="text-6xl font-black text-white airport-font">{stats.finalizado}</span>
            <span className="text-xs font-bold text-slate-500 uppercase tracking-widest">Viagens</span>
          </div>
          <div className="flex items-center gap-2 text-emerald-400/80 font-black text-xs airport-font uppercase">
            <Bird size={14} /> {stats.avesFinalizado.toLocaleString()} Aves Processadas
          </div>
          <div className="mt-6 w-full bg-emerald-500/5 h-2 rounded-full overflow-hidden border border-emerald-500/10">
            <div className="bg-emerald-500 h-full transition-all duration-1000" style={{ width: filteredAndSortedCargos.length ? `${(stats.finalizado / filteredAndSortedCargos.length) * 100}%` : '0%' }} />
          </div>
        </div>

        <div className="bg-[#0f172a]/40 border border-yellow-500/20 rounded-[2.5rem] p-8 shadow-2xl relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-8 opacity-10 group-hover:scale-125 transition-transform group-hover:-rotate-12">
            <Zap size={80} className="text-yellow-500" />
          </div>
          <p className="text-[10px] font-black uppercase text-yellow-500 tracking-[0.3em] mb-2">Em Execução</p>
          <div className="flex items-baseline gap-4 mb-4">
            <span className="text-6xl font-black text-white airport-font">{stats.carregando}</span>
            <span className="text-xs font-bold text-slate-500 uppercase tracking-widest">Ativas</span>
          </div>
          <div className="flex items-center gap-2 text-yellow-500 font-black text-xs airport-font uppercase">
            <Radio size={14} className="animate-pulse" /> {stats.avesCarregando.toLocaleString()} Aves em Trânsito
          </div>
          <div className="mt-6 w-full bg-yellow-500/5 h-2 rounded-full overflow-hidden border border-yellow-500/10">
            <div className="bg-yellow-500 h-full animate-pulse" style={{ width: filteredAndSortedCargos.length ? `${(stats.carregando / filteredAndSortedCargos.length) * 100}%` : '0%' }} />
          </div>
        </div>

        <div className={`bg-[#0f172a]/40 border rounded-[2.5rem] p-8 shadow-2xl relative overflow-hidden group transition-all duration-500 ${stats.apenasAtrasado > 0 ? 'border-red-500/40 bg-red-500/5' : 'border-sky-500/20'}`}>
          <div className="absolute top-0 right-0 p-8 opacity-10 group-hover:scale-125 transition-transform">
            <Calendar size={80} className={stats.apenasAtrasado > 0 ? 'text-red-500' : 'text-sky-500'} />
          </div>
          <p className={`text-[10px] font-black uppercase tracking-[0.3em] mb-2 ${stats.apenasAtrasado > 0 ? 'text-red-500' : 'text-sky-500'}`}>Programação / Pendentes</p>
          <div className="flex items-baseline gap-4 mb-4">
            <span className="text-6xl font-black text-white airport-font">{stats.programadoAtrasado}</span>
            <span className="text-xs font-bold text-slate-500 uppercase tracking-widest">Total</span>
          </div>
          <div className={`flex items-center gap-2 font-black text-xs airport-font uppercase ${stats.apenasAtrasado > 0 ? 'text-red-500 animate-pulse' : 'text-sky-400'}`}>
             {stats.apenasAtrasado > 0 ? <AlertCircle size={14} /> : <Clock size={14} />}
             {stats.apenasAtrasado > 0 ? `${stats.apenasAtrasado} Cargas com Atraso Crítico` : `${stats.avesProgramadoAtrasado.toLocaleString()} Aves em Fila`}
          </div>
          <div className="mt-6 w-full bg-slate-900 h-2 rounded-full overflow-hidden">
            <div className={`h-full transition-all duration-1000 ${stats.apenasAtrasado > 0 ? 'bg-red-500' : 'bg-sky-500'}`} style={{ width: filteredAndSortedCargos.length ? `${(stats.programadoAtrasado / filteredAndSortedCargos.length) * 100}%` : '0%' }} />
          </div>
        </div>
      </div>

      <div className="rounded-[2.5rem] border border-slate-800 shadow-2xl bg-[#020617] overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left airport-font min-w-[1300px]">
            <thead>
              <tr className="bg-slate-900/60 text-slate-500 text-[11px] uppercase font-black tracking-[0.3em] border-b border-slate-800">
                <th className="px-8 py-6">Estado</th>
                <th className="px-8 py-6">Carga ID</th>
                <th className="px-8 py-6">Voo / Equipe</th>
                <th className="px-8 py-6">Integrado</th>
                <th className="px-8 py-6 text-center">Origem/Cidade</th>
                <th className="px-8 py-6 text-center">Estimativa</th>
                <th className="px-8 py-6 text-center">Abate</th>
                <th className="px-8 py-6 text-center">Quant/Peso</th>
                <th className="px-8 py-6 text-right pr-12">Logística</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-800">
              {filteredAndSortedCargos.length === 0 ? (
                <tr>
                  <td colSpan={9} className="px-8 py-32 text-center text-slate-700">
                    <div className="flex flex-col items-center gap-4">
                      <Radio size={48} className="opacity-10 animate-pulse" />
                      <span className="uppercase font-black tracking-[0.4em] text-xs">
                        {cargos.length > 0 ? 'Nenhum voo encontrado para estes filtros.' : 'Aguardando dados da torre...'}
                      </span>
                    </div>
                  </td>
                </tr>
              ) : (
                filteredAndSortedCargos.map((cargo) => {
                  const pickup = formatDateTime(cargo.pickupTime);
                  const slaughter = formatDateTime(cargo.slaughterTime);
                  const effectiveStatus = getEffectiveStatus(cargo);
                  const isDelayed = effectiveStatus === CargoStatus.ATRASADO;
                  const isLoading = effectiveStatus === CargoStatus.CARREGANDO;

                  return (
                    <tr key={cargo.id} className={`group hover:bg-slate-900/40 transition-all ${isDelayed ? 'row-atrasado-blink' : ''} ${isLoading ? 'row-carregando-blink' : ''}`}>
                      <td className="px-8 py-7">
                        <span className={`px-4 py-1.5 rounded-full border text-[9px] font-black tracking-widest uppercase shadow-xl ${getStatusStyle(effectiveStatus)}`}>
                          {effectiveStatus}
                        </span>
                      </td>
                      <td className="px-8 py-7">
                        <div className="flex items-center gap-3">
                          <div className="w-8 h-8 rounded-lg bg-yellow-500/10 flex items-center justify-center text-yellow-500 border border-yellow-500/20">
                            <Hash size={14} />
                          </div>
                          <span className="text-yellow-500 font-black text-2xl drop-shadow-[0_0_10px_rgba(234,179,8,0.3)]">{cargo.cargoNumber}</span>
                        </div>
                      </td>
                      <td className="px-8 py-7">
                        <div className="font-black text-white text-base leading-none mb-1 group-hover:translate-x-1 transition-transform">{getTeamLabel(cargo.teamId)}</div>
                        <div className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">{cargo.unit}</div>
                      </td>
                      <td className="px-8 py-7">
                         <div className="text-slate-300 font-bold uppercase text-sm leading-tight">{cargo.integrated}</div>
                         <div className="text-[9px] text-slate-600 font-black uppercase mt-1">Produtor Cadastrado</div>
                      </td>
                      <td className="px-8 py-7 text-center">
                        <span className="text-slate-400 text-sm uppercase font-black tracking-tighter">{cargo.city}</span>
                      </td>

                      <td className="px-8 py-7 text-center">
                        <div className={`font-black text-2xl ${isDelayed || isLoading ? 'text-white' : 'text-sky-400'} glow-text`}>
                          {pickup.time}
                        </div>
                        <div className="text-[9px] font-black uppercase text-slate-600 tracking-widest mt-1">{pickup.date}</div>
                      </td>

                      <td className="px-8 py-7 text-center">
                        <div className="font-black text-2xl text-yellow-500/80">
                          {slaughter.time}
                        </div>
                        <div className="text-[9px] font-black uppercase text-slate-600 tracking-widest mt-1">{slaughter.date}</div>
                      </td>

                      <td className="px-8 py-7 text-center">
                        <div className="font-black text-white text-base leading-none mb-1">{cargo.birdCount.toLocaleString()}</div>
                        <div className="text-[10px] text-slate-500 font-bold uppercase tracking-tight">{cargo.totalLoad.toLocaleString()} KG</div>
                      </td>

                      <td className="px-8 py-7 text-right pr-12">
                        <div className="flex items-center justify-end gap-4 opacity-0 group-hover:opacity-100 transition-all translate-x-4 group-hover:translate-x-0">
                          {cargo.status === CargoStatus.PROGRAMADO && (
                            <button onClick={() => onStart(cargo.id)} className="flex items-center gap-2 px-5 py-2.5 bg-sky-500 text-slate-950 rounded-xl font-black text-[10px] uppercase hover:bg-white transition-all shadow-xl">
                              <Play size={14} fill="currentColor" /> Devolver
                            </button>
                          )}
                          {cargo.status === CargoStatus.CARREGANDO && (
                            <button onClick={() => onEnd(cargo.id)} className="flex items-center gap-2 px-5 py-2.5 bg-emerald-500 text-slate-950 rounded-xl font-black text-[10px] uppercase hover:bg-white transition-all shadow-xl animate-pulse">
                              <CheckCircle size={14} /> Pousar
                            </button>
                          )}
                          <div className="flex gap-2">
                            <button onClick={() => onEdit(cargo)} className="p-3 text-slate-500 hover:text-yellow-500 hover:bg-yellow-500/10 rounded-xl transition-all border border-transparent hover:border-yellow-500/20"><Edit2 size={16} /></button>
                            <button onClick={() => onDelete(cargo.id)} className="p-3 text-slate-500 hover:text-red-500 hover:bg-red-500/10 rounded-xl transition-all border border-transparent hover:border-red-500/20"><Trash2 size={16} /></button>
                          </div>
                        </div>
                        {cargo.status === CargoStatus.FINALIZADO && (
                           <div className="text-right text-[10px] font-black leading-tight text-emerald-500/50 uppercase tracking-widest">
                             Finalizado em {cargo.endDate} • {cargo.endTime}
                           </div>
                        )}
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Play, 
  CheckCircle, 
  Trash2, 
  Edit2, 
  AlertCircle, 
  ListX, 
  Clock, 
  Calendar, 
  Zap, 
  Bird, 
  Hash, 
  Radio, 
  Filter, 
  XCircle,
  Building2,
  Users as UsersIcon
} from 'lucide-react';
import { Cargo, Team, CargoStatus, Unit } from '../types';

interface AirportBoardProps {
  cargos: Cargo[];
  teams: Team[];
  units: Unit[];
  onStart: (id: string) => void;
  onEnd: (id: string) => void;
  onDelete: (id: string) => void;
  onEdit: (cargo: Cargo) => void;
  onClearAll: () => void;
}

export const AirportBoard: React.FC<AirportBoardProps> = ({ 
  cargos, 
  teams, 
  units,
  onStart, 
  onEnd, 
  onDelete, 
  onEdit,
  onClearAll
}) => {
  const [now, setNow] = useState(new Date());

  // Filtros
  const [filterUnitId, setFilterUnitId] = useState('');
  const [filterTeamId, setFilterTeamId] = useState('');
  const [filterSlaughterDate, setFilterSlaughterDate] = useState('');

  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 10000);
    return () => clearInterval(timer);
  }, []);

  const getTeamLabel = (teamId: string) => {
    const team = teams.find(t => t.id === teamId);
    return team ? `EQP ${team.number}` : '---';
  };

  const getEffectiveStatus = (cargo: Cargo): CargoStatus => {
    if (cargo.status === CargoStatus.PROGRAMADO) {
      const scheduledDate = new Date(cargo.pickupTime);
      if (now > scheduledDate) return CargoStatus.ATRASADO;
    }
    return cargo.status;
  };

  const formatDateTime = (isoString: string): { date: string; time: string; isPast: boolean } => {
    if (!isoString) return { date: '---', time: '---', isPast: false };
    try {
      const scheduledDate = new Date(isoString);
      if (isNaN(scheduledDate.getTime())) return { date: '---', time: isoString || '---', isPast: false };
      return {
        date: scheduledDate.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' }),
        time: scheduledDate.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
        isPast: now > scheduledDate
      };
    } catch {
      return { date: '---', time: isoString || '---', isPast: false };
    }
  };

  const getStatusStyle = (status: CargoStatus) => {
    switch (status) {
      case CargoStatus.PROGRAMADO: return 'text-sky-400 bg-sky-400/5 border-sky-400/30';
      case CargoStatus.CARREGANDO: return 'text-slate-950 bg-yellow-500 border-yellow-500 font-black shadow-[0_0_15px_rgba(234,179,8,0.4)]';
      case CargoStatus.FINALIZADO: return 'text-emerald-400 bg-emerald-400/5 border-emerald-400/30';
      case CargoStatus.ATRASADO: return 'text-white bg-red-600 border-red-500 font-black animate-pulse';
      default: return 'text-slate-400';
    }
  };

  // Lógica de Filtragem e Ordenação
  const filteredAndSortedCargos = useMemo(() => {
    return cargos
      .filter(cargo => {
        const matchesUnit = !filterUnitId || cargo.unitId === filterUnitId;
        const matchesTeam = !filterTeamId || cargo.teamId === filterTeamId;

        let matchesDate = true;
        if (filterSlaughterDate) {
          const cargoDate = cargo.slaughterTime.split('T')[0];
          matchesDate = cargoDate === filterSlaughterDate;
        }

        return matchesUnit && matchesTeam && matchesDate;
      })
      .sort((a, b) => {
        return a.cargoNumber.localeCompare(b.cargoNumber, undefined, { numeric: true, sensitivity: 'base' });
      });
  }, [cargos, filterUnitId, filterTeamId, filterSlaughterDate]);

  const stats = filteredAndSortedCargos.reduce((acc, cargo) => {
    const status = getEffectiveStatus(cargo);
    const birds = cargo.birdCount || 0;
    if (status === CargoStatus.FINALIZADO) { acc.finalizado++; acc.avesFinalizado += birds; }
    else if (status === CargoStatus.CARREGANDO) { acc.carregando++; acc.avesCarregando += birds; }
    else { acc.programadoAtrasado++; acc.avesProgramadoAtrasado += birds; if (status === CargoStatus.ATRASADO) acc.apenasAtrasado++; }
    return acc;
  }, { finalizado: 0, avesFinalizado: 0, carregando: 0, avesCarregando: 0, programadoAtrasado: 0, avesProgramadoAtrasado: 0, apenasAtrasado: 0 });

  const clearFilters = () => {
    setFilterUnitId('');
    setFilterTeamId('');
    setFilterSlaughterDate('');
  };

  return (
    <div className="space-y-6">
      {/* Header Estilo Terminal de Aeroporto - Compactado */}
      <div className="flex flex-col lg:flex-row lg:items-end justify-between gap-6 pb-6 border-b border-slate-800">
        <div className="space-y-3">
          <div className="flex items-center gap-3">
            <span className="px-2 py-0.5 bg-yellow-500 text-slate-950 text-[9px] font-black uppercase tracking-widest rounded">AO VIVO</span>
            <div className="h-px w-12 bg-slate-800" />
            <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Sincronizado com Torre</span>
          </div>
          <h2 className="text-4xl font-black uppercase tracking-tighter text-white airport-font">
            CargoFlight<span className="text-yellow-500">Board</span>
          </h2>
          <div className="flex items-center gap-4">
            <p className="text-slate-500 text-[10px] font-bold uppercase tracking-[0.2em]">Fluxo Operacional de Logística</p>
            {cargos.length > 0 && (
              <button 
                onClick={onClearAll}
                className="flex items-center gap-2 text-[9px] font-black text-red-500 hover:text-white transition-all uppercase bg-red-500/5 hover:bg-red-600 px-3 py-1.5 rounded-lg border border-red-500/20"
              >
                <ListX size={12} /> Limpar Painel
              </button>
            )}
          </div>
        </div>

        <div className="flex flex-wrap gap-3 p-3 bg-slate-900/40 rounded-2xl border border-slate-800 backdrop-blur-md">
          <div className="flex items-center gap-2 text-[9px] font-black uppercase text-sky-400">
            <div className="w-2 h-2 rounded-full bg-sky-400" /> PROGRAMADO
          </div>
          <div className="flex items-center gap-2 text-[9px] font-black uppercase text-red-500">
            <div className="w-2 h-2 rounded-full bg-red-500 animate-ping" /> ATRASADO
          </div>
          <div className="flex items-center gap-2 text-[9px] font-black uppercase text-yellow-400">
            <div className="w-2 h-2 rounded-full bg-yellow-400 animate-pulse" /> CARREGANDO
          </div>
          <div className="flex items-center gap-2 text-[9px] font-black uppercase text-emerald-400">
            <div className="w-2 h-2 rounded-full bg-emerald-400" /> FINALIZADO
          </div>
        </div>
      </div>

      {/* Painel de Filtros - Compactado */}
      <div className="bg-[#0f172a]/40 backdrop-blur-xl border border-slate-800 rounded-2xl p-4 shadow-xl border-t-white/5">
        <div className="flex flex-col md:flex-row items-center gap-4">
          <div className="flex items-center gap-2 text-yellow-500 shrink-0">
            <Filter size={16} />
            <span className="text-[9px] font-black uppercase tracking-[0.2em]">Filtros</span>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 flex-1 w-full">
            <div className="relative group">
              <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-500">
                <Building2 size={12} />
              </div>
              <select 
                value={filterUnitId}
                onChange={(e) => setFilterUnitId(e.target.value)}
                className="w-full bg-black/40 border border-slate-800 text-white rounded-lg py-2 pl-8 pr-3 outline-none focus:border-yellow-500/50 transition-all text-[10px] font-black uppercase appearance-none cursor-pointer"
              >
                <option value="">Unidades</option>
                {units.map(u => (
                  <option key={u.id} value={u.id}>{u.name}</option>
                ))}
              </select>
            </div>

            <div className="relative group">
              <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-500">
                <UsersIcon size={12} />
              </div>
              <select 
                value={filterTeamId}
                onChange={(e) => setFilterTeamId(e.target.value)}
                className="w-full bg-black/40 border border-slate-800 text-white rounded-lg py-2 pl-8 pr-3 outline-none focus:border-yellow-500/50 transition-all text-[10px] font-black uppercase appearance-none cursor-pointer"
              >
                <option value="">Equipes</option>
                {teams.map(t => (
                  <option key={t.id} value={t.id}>EQP {t.number}</option>
                ))}
              </select>
            </div>

            <div className="relative group">
              <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-500">
                <Calendar size={12} />
              </div>
              <input 
                type="date"
                value={filterSlaughterDate}
                onChange={(e) => setFilterSlaughterDate(e.target.value)}
                className="w-full bg-black/40 border border-slate-800 text-white rounded-lg py-2 pl-8 pr-3 outline-none focus:border-yellow-500/50 transition-all text-[10px] font-black uppercase cursor-pointer"
              />
            </div>
          </div>

          {(filterUnitId || filterTeamId || filterSlaughterDate) && (
            <button 
              onClick={clearFilters}
              className="flex items-center gap-1.5 px-4 py-2 rounded-lg bg-slate-800 hover:bg-slate-700 text-white text-[9px] font-black uppercase tracking-widest transition-all"
            >
              <XCircle size={12} /> Limpar
            </button>
          )}
        </div>
      </div>

      {/* Cartões de Estatísticas Reduzidos */}
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
        <div className="bg-[#0f172a]/40 border border-emerald-500/20 rounded-2xl p-5 shadow-2xl relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:scale-110 transition-transform">
            <CheckCircle size={48} className="text-emerald-500" />
          </div>
          <p className="text-[9px] font-black uppercase text-emerald-500 tracking-[0.2em] mb-1">Completados</p>
          <div className="flex items-baseline gap-2 mb-2">
            <span className="text-4xl font-black text-white airport-font leading-none">{stats.finalizado}</span>
            <span className="text-[9px] font-bold text-slate-500 uppercase tracking-widest">Viagens</span>
          </div>
          <div className="flex items-center gap-1.5 text-emerald-400/80 font-black text-[10px] airport-font uppercase">
            <Bird size={12} /> {stats.avesFinalizado.toLocaleString()} Aves
          </div>
          <div className="mt-4 w-full bg-emerald-500/5 h-1.5 rounded-full overflow-hidden border border-emerald-500/10">
            <div className="bg-emerald-500 h-full transition-all duration-1000" style={{ width: filteredAndSortedCargos.length ? `${(stats.finalizado / filteredAndSortedCargos.length) * 100}%` : '0%' }} />
          </div>
        </div>

        <div className="bg-[#0f172a]/40 border border-yellow-500/20 rounded-2xl p-5 shadow-2xl relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:scale-110 transition-transform">
            <Zap size={48} className="text-yellow-500" />
          </div>
          <p className="text-[9px] font-black uppercase text-yellow-500 tracking-[0.2em] mb-1">Em Execução</p>
          <div className="flex items-baseline gap-2 mb-2">
            <span className="text-4xl font-black text-white airport-font leading-none">{stats.carregando}</span>
            <span className="text-[9px] font-bold text-slate-500 uppercase tracking-widest">Ativas</span>
          </div>
          <div className="flex items-center gap-1.5 text-yellow-500 font-black text-[10px] airport-font uppercase">
            <Radio size={12} className="animate-pulse" /> {stats.avesCarregando.toLocaleString()} Aves
          </div>
          <div className="mt-4 w-full bg-yellow-500/5 h-1.5 rounded-full overflow-hidden border border-yellow-500/10">
            <div className="bg-yellow-500 h-full animate-pulse" style={{ width: filteredAndSortedCargos.length ? `${(stats.carregando / filteredAndSortedCargos.length) * 100}%` : '0%' }} />
          </div>
        </div>

        <div className={`bg-[#0f172a]/40 border rounded-2xl p-5 shadow-2xl relative overflow-hidden group transition-all duration-500 ${stats.apenasAtrasado > 0 ? 'border-red-500/40 bg-red-500/5' : 'border-sky-500/20'}`}>
          <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:scale-110 transition-transform">
            <Calendar size={48} className={stats.apenasAtrasado > 0 ? 'text-red-500' : 'text-sky-500'} />
          </div>
          <p className={`text-[9px] font-black uppercase tracking-[0.2em] mb-1 ${stats.apenasAtrasado > 0 ? 'text-red-500' : 'text-sky-500'}`}>Programação</p>
          <div className="flex items-baseline gap-2 mb-2">
            <span className="text-4xl font-black text-white airport-font leading-none">{stats.programadoAtrasado}</span>
            <span className="text-[9px] font-bold text-slate-500 uppercase tracking-widest">Total</span>
          </div>
          <div className={`flex items-center gap-1.5 font-black text-[10px] airport-font uppercase ${stats.apenasAtrasado > 0 ? 'text-red-500 animate-pulse' : 'text-sky-400'}`}>
             {stats.apenasAtrasado > 0 ? <AlertCircle size={12} /> : <Clock size={12} />}
             {stats.apenasAtrasado > 0 ? `${stats.apenasAtrasado} Atrasos` : `${stats.avesProgramadoAtrasado.toLocaleString()} Em Fila`}
          </div>
          <div className="mt-4 w-full bg-slate-900 h-1.5 rounded-full overflow-hidden">
            <div className={`h-full transition-all duration-1000 ${stats.apenasAtrasado > 0 ? 'bg-red-500' : 'bg-sky-500'}`} style={{ width: filteredAndSortedCargos.length ? `${(stats.programadoAtrasado / filteredAndSortedCargos.length) * 100}%` : '0%' }} />
          </div>
        </div>
      </div>

      {/* Tabela de Voos */}
      <div className="rounded-2xl border border-slate-800 shadow-2xl bg-[#020617] overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left airport-font min-w-[1200px]">
            <thead>
              <tr className="bg-slate-900/60 text-slate-500 text-[10px] uppercase font-black tracking-[0.2em] border-b border-slate-800">
                <th className="px-6 py-4">Estado</th>
                <th className="px-6 py-4">Carga ID</th>
                <th className="px-6 py-4">Equipe / Unidade</th>
                <th className="px-6 py-4">Integrado</th>
                <th className="px-6 py-4 text-center">Origem</th>
                <th className="px-6 py-4 text-center">Apanha</th>
                <th className="px-6 py-4 text-center">Abate</th>
                <th className="px-6 py-4 text-center">Quant/Peso</th>
                <th className="px-6 py-4 text-right pr-10">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-800">
              {filteredAndSortedCargos.length === 0 ? (
                <tr>
                  <td colSpan={9} className="px-6 py-20 text-center text-slate-700">
                    <div className="flex flex-col items-center gap-3">
                      <Radio size={32} className="opacity-10 animate-pulse" />
                      <span className="uppercase font-black tracking-[0.2em] text-[10px]">
                        {cargos.length > 0 ? 'Nenhum voo encontrado.' : 'Aguardando torre...'}
                      </span>
                    </div>
                  </td>
                </tr>
              ) : (
                filteredAndSortedCargos.map((cargo) => {
                  const pickup = formatDateTime(cargo.pickupTime);
                  const slaughter = formatDateTime(cargo.slaughterTime);
                  const effectiveStatus = getEffectiveStatus(cargo);
                  const isDelayed = effectiveStatus === CargoStatus.ATRASADO;
                  const isLoading = effectiveStatus === CargoStatus.CARREGANDO;

                  return (
                    <tr key={cargo.id} className={`group hover:bg-slate-900/40 transition-all ${isDelayed ? 'row-atrasado-blink' : ''} ${isLoading ? 'row-carregando-blink' : ''}`}>
                      <td className="px-6 py-4">
                        <span className={`px-2 py-1 rounded-md border text-[8px] font-black tracking-widest uppercase ${getStatusStyle(effectiveStatus)}`}>
                          {effectiveStatus}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-2">
                          <span className="text-yellow-500 font-black text-lg drop-shadow-[0_0_8px_rgba(234,179,8,0.2)]">{cargo.cargoNumber}</span>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="font-black text-white text-sm group-hover:translate-x-1 transition-transform">{getTeamLabel(cargo.teamId)}</div>
                        <div className="text-[9px] text-slate-500 uppercase font-bold tracking-widest">{cargo.unit}</div>
                      </td>
                      <td className="px-6 py-4">
                         <div className="text-slate-300 font-bold uppercase text-xs truncate max-w-[150px]">{cargo.integrated}</div>
                      </td>
                      <td className="px-6 py-4 text-center">
                        <span className="text-slate-400 text-[11px] uppercase font-black">{cargo.city}</span>
                      </td>

                      <td className="px-6 py-4 text-center">
                        <div className={`font-black text-lg ${isDelayed || isLoading ? 'text-white' : 'text-sky-400'} glow-text leading-none`}>
                          {pickup.time}
                        </div>
                        <div className="text-[8px] font-black uppercase text-slate-600 mt-0.5">{pickup.date}</div>
                      </td>

                      <td className="px-6 py-4 text-center">
                        <div className="font-black text-lg text-yellow-500/80 leading-none">
                          {slaughter.time}
                        </div>
                        <div className="text-[8px] font-black uppercase text-slate-600 mt-0.5">{slaughter.date}</div>
                      </td>

                      <td className="px-6 py-4 text-center">
                        <div className="font-black text-white text-sm leading-none">{cargo.birdCount.toLocaleString()}</div>
                        <div className="text-[9px] text-slate-500 font-bold uppercase tracking-tight mt-0.5">{cargo.totalLoad.toLocaleString()} KG</div>
                      </td>

                      <td className="px-6 py-4 text-right pr-10">
                        <div className="flex items-center justify-end gap-3 opacity-0 group-hover:opacity-100 transition-all translate-x-2 group-hover:translate-x-0">
                          {cargo.status === CargoStatus.PROGRAMADO && (
                            <button onClick={() => onStart(cargo.id)} className="px-3 py-1.5 bg-sky-500 text-slate-950 rounded-lg font-black text-[9px] uppercase hover:bg-white transition-all">
                              Devolver
                            </button>
                          )}
                          {cargo.status === CargoStatus.CARREGANDO && (
                            <button onClick={() => onEnd(cargo.id)} className="px-3 py-1.5 bg-emerald-500 text-slate-950 rounded-lg font-black text-[9px] uppercase hover:bg-white transition-all animate-pulse">
                              Pousar
                            </button>
                          )}
                          <button onClick={() => onEdit(cargo)} className="p-1.5 text-slate-500 hover:text-yellow-500"><Edit2 size={14} /></button>
                          <button onClick={() => onDelete(cargo.id)} className="p-1.5 text-slate-500 hover:text-red-500"><Trash2 size={14} /></button>
                        </div>
                        {cargo.status === CargoStatus.FINALIZADO && (
                           <div className="text-right text-[8px] font-black text-emerald-500/40 uppercase">
                             {cargo.endDate} {cargo.endTime}
                           </div>
                        )}
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
