                  <div className="flex items-center gap-3">
                    <div className="w-1.5 h-1.5 rounded-full bg-slate-700 group-hover:bg-yellow-500 group-hover:shadow-[0_0_10px_rgba(234,179,8,0.5)] transition-all" />
